SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a semicircular wire of radius R carrying current I is:", "explanation": "A semicircular arc subtends an angle π at the centre. The field due to a circular arc subtending angle φ at the centre is B = μ₀Iφ/(4πR). For a semicircle, φ = π, so B = μ₀Iπ/(4πR) = μ₀I/(4R). The direction is perpendicular to the plane of the semicircle, determined by the right-hand rule.", "correct_answer": "B", "concept_tags": ["semicircular-arc", "magnetic-field", "biot-savart-law"], "payload": {"question_id": "cuet-phy-mag-biot-15", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(2R)", "is_correct": false}, {"key": "B", "text": "μ₀I/(4R)", "is_correct": true}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀I/(8R)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(2R) is the field at the centre of a full circular loop. A semicircle is half the loop, so its contribution is half: μ₀I/(4R).", "misconception": "Using full loop formula for semicircle"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the field due to a long straight wire at distance R. The semicircular arc formula is μ₀I/(4R).", "misconception": "Confusing straight wire formula with arc formula"}, {"option_key": "D", "hint": "μ₀I/(8R) would be the field due to a quarter-circle arc, not a semicircle. A semicircle subtends angle π, giving μ₀I/(4R).", "misconception": "Using quarter-circle result instead of semicircle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A toroid has 500 turns, a mean radius of 0.2 m, and carries a current of 3 A. The magnetic field inside the toroid is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a toroid, applying Ampere''s law: B × 2πr = μ₀NI, so B = μ₀NI/(2πr). B = (4π × 10⁻⁷ × 500 × 3)/(2π × 0.2) = (4π × 1.5 × 10⁻⁴)/(0.4π) = (6π × 10⁻⁴)/(0.4π) = 6 × 10⁻⁴/0.4 = 1.5 × 10⁻³ T = 1.5 mT.", "correct_answer": "B", "concept_tags": ["toroid", "ampere-law", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-biot-16", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "3.0 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "1.5 × 10⁻³ T", "is_correct": true}, {"key": "C", "text": "7.5 × 10⁻⁴ T", "is_correct": false}, {"key": "D", "text": "1.5 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is double the correct value. You may have used r = 0.1 m instead of the given mean radius r = 0.2 m in B = μ₀NI/(2πr).", "misconception": "Using radius instead of diameter, or halving the radius"}, {"option_key": "C", "hint": "This is half the correct answer. Check if you accidentally doubled the radius or halved the current in your calculation.", "misconception": "Arithmetic error in substitution"}, {"option_key": "D", "hint": "This is off by a factor of 10. Recheck: μ₀NI = 4π × 10⁻⁷ × 500 × 3 = 6π × 10⁻⁴, and dividing by 2π × 0.2 = 0.4π gives 1.5 × 10⁻³.", "misconception": "Power of 10 error in computation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A circular loop of radius R carries current I. At a large distance x (x >> R) along its axis, the magnetic field varies as:", "explanation": "The magnetic field on the axis of a circular loop is B = (μ₀IR²)/(2(R² + x²)^(3/2)). When x >> R, R² + x² ≈ x², so (R² + x²)^(3/2) ≈ x³. Therefore B ≈ μ₀IR²/(2x³), which shows B ∝ 1/x³. This is identical to the far-field behaviour of a magnetic dipole, where B ∝ 1/x³ along the axis.", "correct_answer": "D", "concept_tags": ["circular-loop-axis", "far-field", "magnetic-dipole"], "payload": {"question_id": "cuet-phy-mag-biot-17", "subtopic": "Magnetic field due to circular loop on axis", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "B ∝ 1/x", "is_correct": false}, {"key": "B", "text": "B ∝ 1/x²", "is_correct": false}, {"key": "C", "text": "B ∝ 1/x⁴", "is_correct": false}, {"key": "D", "text": "B ∝ 1/x³", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1/x dependence applies to an infinite straight wire, not a circular loop at large distances.", "misconception": "Confusing straight-wire field with loop field"}, {"option_key": "B", "hint": "1/x² would be for a point charge electric field (Coulomb''s law). The loop behaves as a dipole with 1/x³.", "misconception": "Applying inverse-square law to a magnetic dipole"}, {"option_key": "C", "hint": "The exponent 3 comes from (x²)^(3/2) = x³. A 1/x⁴ dependence would require a quadrupole.", "misconception": "Overestimating the power in the far-field approximation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire is bent into a shape consisting of a semicircular arc of radius R connected to two straight segments, each extending radially from the ends of the arc to a point at distance 2R from the centre, and then connected by another semicircular arc of radius 2R (same centre). A current I flows through this composite loop. The magnetic field at the common centre is:", "explanation": "The straight radial segments contribute zero field at the centre because for them, dl is parallel to r̂ (sinθ = 0). The inner semicircle of radius R contributes B₁ = μ₀I/(4R) (using the semicircle formula μ₀I/(4R), directed out of the plane, say). The outer semicircle of radius 2R contributes B₂ = μ₀I/(4 × 2R) = μ₀I/(8R) in the opposite direction (since current flows in the opposite sense around the centre). Net field = μ₀I/(4R) − μ₀I/(8R) = μ₀I/(8R), directed out of the plane.", "correct_answer": "C", "concept_tags": ["composite-loop", "semicircular-arcs", "superposition", "biot-savart-law"], "payload": {"question_id": "cuet-phy-mag-biot-18", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "B", "text": "3μ₀I/(8R), directed out of the plane", "is_correct": false}, {"key": "C", "text": "μ₀I/(8R), directed out of the plane", "is_correct": true}, {"key": "D", "text": "3μ₀I/(4R), directed into the plane", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the field due to only the inner semicircular arc. You must also subtract the contribution of the outer semicircular arc, which opposes the inner one.", "misconception": "Ignoring the contribution of the outer semicircular arc"}, {"option_key": "B", "hint": "3μ₀I/(8R) would result from adding the two semicircular contributions instead of subtracting. The current traverses the two arcs in opposite senses relative to the centre, so the fields oppose each other.", "misconception": "Adding fields instead of subtracting due to opposite current directions"}, {"option_key": "D", "hint": "The magnitude and direction are both incorrect. The net field is μ₀I/(4R) − μ₀I/(8R) = μ₀I/(8R), and its direction is that of the larger contribution (inner arc).", "misconception": "Errors in both magnitude and direction determination"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire of length L carrying current I is bent into a regular hexagon. The magnetic field at the centre of the hexagon is:", "explanation": "A regular hexagon has 6 sides, each of length L/6. The perpendicular distance from the centre to each side is d = (L/6)(√3/2) = L√3/12. Each side subtends angles α = β = 30° at the foot of the perpendicular from the centre. The field due to one side at the centre is B₁ = (μ₀I/4πd)(sin30° + sin30°) = (μ₀I/4πd)(1) = μ₀I/(4πd). Substituting d = L√3/12: B₁ = μ₀I/(4π × L√3/12) = 12μ₀I/(4πL√3) = 3μ₀I/(πL√3) = √3μ₀I/(πL). For 6 sides, all fields point in the same direction, so B = 6B₁ = 6√3μ₀I/(πL).", "correct_answer": "B", "concept_tags": ["regular-polygon", "straight-conductor", "superposition"], "payload": {"question_id": "cuet-phy-mag-biot-19", "subtopic": "Superposition of magnetic fields", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "3√3μ₀I/(πL)", "is_correct": false}, {"key": "B", "text": "6√3μ₀I/(πL)", "is_correct": true}, {"key": "C", "text": "2√3μ₀I/(πL)", "is_correct": false}, {"key": "D", "text": "12√3μ₀I/(πL)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This accounts for only 3 of the 6 sides. All six sides contribute equally and in the same direction.", "misconception": "Thinking opposite sides cancel each other"}, {"option_key": "C", "hint": "This would correspond to only 2 sides contributing. Recheck the multiplication factor.", "misconception": "Incorrect count of contributing sides"}, {"option_key": "D", "hint": "This is double the correct answer. Verify the field per side calculation carefully.", "misconception": "Error in computing the perpendicular distance to the centre"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two concentric coplanar circular loops have radii R and 2R. The smaller loop carries current I in the anticlockwise direction and the larger loop carries current 2I in the clockwise direction, as seen from the same side. The magnetic field at the common centre is:", "explanation": "Field due to smaller loop (anticlockwise, out of plane): B₁ = μ₀I/(2R), directed outward. Field due to larger loop (clockwise, into plane): B₂ = μ₀(2I)/(2 × 2R) = μ₀I/(2R), directed inward. Since B₁ and B₂ are equal in magnitude but opposite in direction, the net field at the centre is zero.", "correct_answer": "A", "concept_tags": ["concentric-loops", "superposition", "magnetic-field-direction"], "payload": {"question_id": "cuet-phy-mag-biot-20", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "Zero", "is_correct": true}, {"key": "B", "text": "μ₀I/(2R), directed out of the plane", "is_correct": false}, {"key": "C", "text": "μ₀I/R, directed into the plane", "is_correct": false}, {"key": "D", "text": "3μ₀I/(4R), directed out of the plane", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This ignores the contribution of the larger loop. Both loops contribute fields at the centre; you must find the vector sum. The two fields are equal and opposite, giving zero.", "misconception": "Considering only the smaller loop"}, {"option_key": "C", "hint": "The magnitudes are B₁ = μ₀I/(2R) (out) and B₂ = μ₀(2I)/(4R) = μ₀I/(2R) (in). These cancel out; they do not add to μ₀I/R.", "misconception": "Adding magnitudes instead of using vector directions"}, {"option_key": "D", "hint": "This does not correspond to any correct combination of the two fields. Compute each field using B = μ₀I/(2R) and apply superposition with correct directions.", "misconception": "Error in applying superposition principle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows a long straight wire carrying current I in the upward direction. What is the direction of the magnetic field at point P located to the right of the wire?", "explanation": "Using the right-hand rule for a straight current-carrying wire: point the thumb of the right hand in the direction of current (upward). The curled fingers indicate the direction of the magnetic field. At point P (to the right), the fingers point out of the page (toward the observer). Therefore the field at P is directed out of the page.", "correct_answer": "B", "concept_tags": ["right-hand-rule", "straight-wire", "field-direction"], "payload": {"question_id": "cuet-phy-mag-biot-21", "subtopic": "Right-hand rule and direction of B", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "Into the page", "is_correct": false}, {"key": "B", "text": "Out of the page", "is_correct": true}, {"key": "C", "text": "Upward, parallel to the current", "is_correct": false}, {"key": "D", "text": "Toward the wire", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Into the page would be the direction at a point to the left of the wire, not to the right.", "misconception": "Reversing the right-hand rule direction"}, {"option_key": "C", "hint": "Magnetic field lines form closed loops around the wire; they are never parallel to the current.", "misconception": "Confusing electric and magnetic field directions"}, {"option_key": "D", "hint": "Magnetic field lines are tangential to circles around the wire, not radial.", "misconception": "Confusing with electric field of a line charge"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a wire bent into a semicircular arc of radius R connected to two long straight segments. A current I flows through the wire as shown. The magnetic field at the centre O of the semicircle is:", "explanation": "The two straight segments pass through (or their extensions pass through) the centre O. For a straight wire, the field at any point along its own line is zero because the angle between dl and r̂ is 0° or 180°, making the cross product zero. Only the semicircular arc contributes. The field at the centre of a semicircular arc is B = μ₀I/(4R), directed into or out of the page depending on the current direction.", "correct_answer": "A", "concept_tags": ["semicircular-arc", "straight-segment-contribution", "superposition"], "payload": {"question_id": "cuet-phy-mag-biot-22", "subtopic": "Magnetic field at centre of arc/semicircle", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(4R), due to the semicircular part only", "is_correct": true}, {"key": "B", "text": "μ₀I/(2R), due to both straight and curved parts", "is_correct": false}, {"key": "C", "text": "μ₀I/(4R) + μ₀I/(2πR), including straight wire contributions", "is_correct": false}, {"key": "D", "text": "Zero, because the straight parts cancel the semicircular contribution", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "μ₀I/(2R) is for a complete circular loop. A semicircle gives half this value, and the straight parts contribute zero at O.", "misconception": "Treating the semicircle as a full loop"}, {"option_key": "C", "hint": "The straight segments produce zero field at O because the current direction is along the line joining dl and O (sinθ = 0).", "misconception": "Assuming straight segments always contribute to the field"}, {"option_key": "D", "hint": "The straight parts give zero field at O, not a field that cancels the semicircular contribution.", "misconception": "Incorrectly applying superposition with cancellation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows two concentric circular loops of radii R and 2R lying in the same plane, carrying currents I and 2I respectively in opposite directions. The net magnetic field at the common centre O is:", "explanation": "The field at the centre due to the inner loop is B₁ = μ₀I/(2R), directed into the page (for clockwise current). The field due to the outer loop is B₂ = μ₀(2I)/(2 × 2R) = μ₀I/(2R), directed out of the page (for anticlockwise current). Since the currents are in opposite directions, B₁ and B₂ are in opposite directions with equal magnitudes. Therefore the net field at O is B₁ − B₂ = 0.", "correct_answer": "C", "concept_tags": ["concentric-loops", "superposition", "field-cancellation"], "payload": {"question_id": "cuet-phy-mag-biot-23", "subtopic": "Superposition of magnetic fields", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "μ₀I/(2R), into the page", "is_correct": false}, {"key": "B", "text": "μ₀I/(2R), out of the page", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "μ₀I/R, into the page", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is only the field from the inner loop. You must also account for the outer loop''s opposing field.", "misconception": "Ignoring the contribution of the outer loop"}, {"option_key": "B", "hint": "This is only the field from the outer loop. Both loops must be considered together.", "misconception": "Ignoring the contribution of the inner loop"}, {"option_key": "D", "hint": "The fields oppose each other and are equal in magnitude, so they cancel rather than add.", "misconception": "Adding magnitudes without considering direction"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The diagram shows a wire carrying current I bent into the shape of two concentric semicircular arcs of radii R₁ and R₂ (R₂ > R₁) connected by two straight radial segments. The net magnetic field at the common centre O is:", "explanation": "The straight radial segments pass through centre O, so they contribute zero field (dl is parallel to r̂, making the cross product zero). The inner semicircular arc (upper) produces B₁ = μ₀I/(4R₁) in one direction. The outer semicircular arc (lower) carries current in the opposite sense relative to O, so it produces B₂ = μ₀I/(4R₂) in the same direction as B₁ (both into or both out of the page, since the current traverses them in the same rotational sense around O). The net field is B = (μ₀I/4)(1/R₁ + 1/R₂).", "correct_answer": "D", "concept_tags": ["composite-loop", "semicircular-arcs", "superposition", "radial-segments"], "payload": {"question_id": "cuet-phy-mag-biot-24", "subtopic": "Magnetic field at centre of arc/semicircle", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "(μ₀I/4)(1/R₁ − 1/R₂)", "is_correct": false}, {"key": "B", "text": "μ₀I/(4R₁) only, as the outer arc contribution is negligible", "is_correct": false}, {"key": "C", "text": "μ₀I/(4R₂) only, as the inner arc contribution cancels with the straight parts", "is_correct": false}, {"key": "D", "text": "(μ₀I/4)(1/R₁ + 1/R₂)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Subtraction would apply if the two arcs produced fields in opposite directions. Trace the current carefully: both arcs create fields in the same direction at O.", "misconception": "Incorrectly assuming opposite field directions for the two arcs"}, {"option_key": "B", "hint": "The outer arc also contributes to the field. A larger radius gives a smaller but non-zero contribution.", "misconception": "Neglecting the outer arc''s contribution"}, {"option_key": "C", "hint": "Straight radial segments produce zero field at O (dl ∥ r̂), so they cannot cancel anything.", "misconception": "Thinking radial segments contribute to the field"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Both Biot-Savart law and Coulomb''s law are inverse-square laws, but the Biot-Savart law has an additional angle dependence through the cross product.\n\nReason (R): In Biot-Savart law, the magnetic field depends on sinθ (from dl × r̂), whereas in Coulomb''s law, the electric field has no such angular dependence for a point charge.", "explanation": "Both statements are correct. The Biot-Savart law dB = (μ₀/4π)(Idl × r̂)/r² is an inverse-square law like Coulomb''s law F = (1/4πε₀)(q₁q₂/r²)r̂, but it has an extra sinθ factor from the cross product. Coulomb''s law for a point charge is spherically symmetric with no angular dependence. Furthermore, R correctly explains why A is true: the cross product dl × r̂ introduces the sinθ factor that makes Biot-Savart angle-dependent, unlike Coulomb''s law.", "correct_answer": "A", "concept_tags": ["biot-savart-coulomb-comparison", "inverse-square-law", "angle-dependence"], "payload": {"question_id": "cuet-phy-mag-biot-25", "subtopic": "Comparison of Biot-Savart with Coulomb''s law", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains why Biot-Savart has angle dependence (sinθ from cross product) while Coulomb''s law does not. This is exactly the explanation for A.", "misconception": "Failing to see the causal link between R and A"}, {"option_key": "C", "hint": "R is factually correct: sinθ does arise from the cross product, and Coulomb''s law for a point charge has no angular dependence.", "misconception": "Incorrectly thinking Coulomb''s law has angular dependence"}, {"option_key": "D", "hint": "A is correct: Biot-Savart law is indeed an inverse-square law with additional angle dependence from the cross product.", "misconception": "Denying that Biot-Savart law is an inverse-square law"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The magnetic field outside an ideal solenoid is zero. Reason (R): Applying Ampere''s circuital law to a rectangular Amperian loop with one side inside and one side outside the solenoid, the contribution from the outside segment is zero because the field there is zero.", "explanation": "Both Assertion and Reason are correct, and R is the correct explanation of A. For an ideal (infinitely long) solenoid, using Ampere''s law with a rectangular loop: ∮B·dl = B_inside × l + 0 + B_outside × l + 0 = μ₀nIl. Since the field is confined inside (by symmetry and superposition arguments), B_outside = 0, and B_inside = μ₀nI. The Reason correctly describes how Ampere''s law is applied with the field outside being zero.", "correct_answer": "A", "concept_tags": ["solenoid", "ampere-law", "ideal-solenoid", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-mag-biot-26", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly describes the Amperian loop analysis that leads to the conclusion in the Assertion. It is not an unrelated fact; it is the specific explanation for why B = 0 outside.", "misconception": "Failing to see the direct causal link between Ampere''s law application and the result"}, {"option_key": "C", "hint": "The Reason is a correct description of how Ampere''s law is applied to an ideal solenoid. The zero field outside is both used as input (from symmetry) and confirmed by the law.", "misconception": "Incorrectly judging the Reason as false"}, {"option_key": "D", "hint": "The Assertion is well-established physics: an ideal infinite solenoid has zero external field. This is a standard NCERT result.", "misconception": "Incorrectly thinking a solenoid produces field outside"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The magnetic field at the centre of a current-carrying circular loop is always perpendicular to the plane of the loop.\n\nReason (R): According to Biot-Savart law, each current element of the loop contributes a field at the centre that lies in the plane of the loop.", "explanation": "Assertion A is correct: at the centre of a circular loop, every current element dl and the position vector r̂ (from the element to the centre) both lie in the plane of the loop. The cross product dl × r̂ is therefore perpendicular to this plane for every element. Since all contributions point in the same perpendicular direction, the net field is perpendicular to the plane. Reason R is incorrect: it states that each element''s contribution lies in the plane, but dl × r̂ is actually perpendicular to the plane, not in it.", "correct_answer": "C", "concept_tags": ["circular-loop-centre", "cross-product-direction", "biot-savart-application"], "payload": {"question_id": "cuet-phy-mag-biot-27", "subtopic": "Magnetic field due to circular loop at centre", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R claims dB lies in the plane, but dB = dl × r̂ is perpendicular to the plane since both dl and r̂ lie in the plane.", "misconception": "Confusing the plane of dl and r̂ with the direction of their cross product"}, {"option_key": "B", "hint": "R is not correct at all. The cross product of two in-plane vectors is always perpendicular to the plane.", "misconception": "Accepting R as correct without verifying the cross-product direction"}, {"option_key": "D", "hint": "A is definitely correct. The symmetry of the loop ensures all dB contributions add up perpendicular to the plane.", "misconception": "Doubting a well-established result about circular loop fields"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Biot-Savart law can be used to determine the magnetic field due to any arbitrary current distribution. Reason (R): Ampere''s circuital law can be conveniently used to calculate magnetic fields only when the system has sufficient symmetry.", "explanation": "Both A and R are correct statements. Biot-Savart law is a general law applicable to any current configuration (though integration may be complex). Ampere''s law, while always true, is practically useful for calculating B only in highly symmetric situations (infinite straight wire, solenoid, toroid). However, R is NOT the explanation for A. The reason Biot-Savart law is general is because it directly integrates the contribution of each current element, not because Ampere''s law has symmetry limitations.", "correct_answer": "B", "concept_tags": ["biot-savart-law", "ampere-law", "symmetry", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-mag-biot-28", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are true, the limitation of Ampere''s law (needing symmetry) does not explain why Biot-Savart law is general. They are independent facts about two different laws.", "misconception": "Assuming that one law''s limitation automatically explains another law''s generality"}, {"option_key": "C", "hint": "The Reason is a correct statement. Ampere''s law is indeed only practically useful for field calculation when high symmetry exists (e.g., infinite wire, solenoid, toroid).", "misconception": "Thinking Ampere''s law always allows easy field computation"}, {"option_key": "D", "hint": "The Assertion is correct. Biot-Savart law is indeed a general law that can be applied to any current distribution by integrating dB contributions from each element.", "misconception": "Thinking Biot-Savart law has limited applicability"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Long straight conductor carrying current I\n(Q) Circular loop of radius R at its centre\n(R) Solenoid with n turns per unit length\n(S) Toroid of mean radius r with N total turns\n\nColumn II:\n(1) B = μ₀nI\n(2) B = μ₀I/(2πd)\n(3) B = μ₀NI/(2πr)\n(4) B = μ₀I/(2R)", "explanation": "P-2: A long straight conductor produces B = μ₀I/(2πd) at perpendicular distance d. Q-4: At the centre of a circular loop, B = μ₀I/(2R). R-1: Inside an ideal solenoid, B = μ₀nI. S-3: Inside a toroid, B = μ₀NI/(2πr). The correct matching is P-2, Q-4, R-1, S-3.", "correct_answer": "C", "concept_tags": ["magnetic-field-formulas", "straight-conductor", "circular-loop", "solenoid", "toroid"], "payload": {"question_id": "cuet-phy-mag-biot-29", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}, {"key": "B", "text": "P-2, Q-3, R-1, S-4", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": true}, {"key": "D", "text": "P-3, Q-4, R-1, S-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P-1 would assign B = μ₀nI to a straight conductor, but that is the solenoid formula. A straight conductor gives B = μ₀I/(2πd).", "misconception": "Confusing solenoid formula with straight wire formula"}, {"option_key": "B", "hint": "Q-3 assigns the toroid formula to the circular loop. The circular loop at centre gives B = μ₀I/(2R), not μ₀NI/(2πr).", "misconception": "Swapping circular loop and toroid formulas"}, {"option_key": "D", "hint": "P-3 assigns the toroid formula to a straight conductor and S-2 assigns the straight wire formula to the toroid. These are swapped.", "misconception": "Interchanging straight conductor and toroid formulas"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Magnetic field on the axis of a circular loop at distance x >> R from centre\n(Q) Magnetic field at the centre of a circular arc subtending angle θ\n(R) Magnetic field inside a solenoid at a point near its end\n(S) Magnetic field at the centre of two concentric coplanar loops of radii R and 2R carrying equal current I in the same direction\n\nColumn II:\n(1) μ₀Iθ/(4πR)\n(2) Approximately μ₀nI/2\n(3) 3μ₀I/(4R)\n(4) Varies as 1/x³ (magnetic dipole behaviour)", "explanation": "P-4: For x >> R, B = μ₀IR²/[2(R² + x²)^(3/2)] ≈ μ₀IR²/(2x³), which varies as 1/x³ like a magnetic dipole. Q-1: The field at the centre of an arc of angle θ is B = μ₀Iθ/(4πR). R-2: At the end of a solenoid, the field is approximately half the interior value, i.e., ≈μ₀nI/2. S-3: B = μ₀I/(2R) + μ₀I/(2×2R) = μ₀I/(2R) + μ₀I/(4R) = 3μ₀I/(4R).", "correct_answer": "D", "concept_tags": ["axial-field", "magnetic-dipole", "arc-formula", "solenoid-end", "superposition"], "payload": {"question_id": "cuet-phy-mag-biot-30", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-4, Q-1, R-3, S-2", "is_correct": false}, {"key": "B", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}, {"key": "C", "text": "P-4, Q-3, R-2, S-1", "is_correct": false}, {"key": "D", "text": "P-4, Q-1, R-2, S-3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "R-3 assigns 3μ₀I/(4R) to the solenoid end field, but that expression involves R (loop radius), not the solenoid parameters. The solenoid end field is ≈μ₀nI/2.", "misconception": "Confusing solenoid end field with concentric loop superposition"}, {"option_key": "B", "hint": "P-1 assigns the arc formula to the far-axis field. The far-axis field follows the dipole 1/x³ dependence, not the arc formula.", "misconception": "Mixing up axial field behaviour with arc field formula"}, {"option_key": "C", "hint": "Q-3 assigns 3μ₀I/(4R) to an arc, but that result comes from superposition of two concentric loops, not a single arc. The arc formula is μ₀Iθ/(4πR).", "misconception": "Confusing arc formula with superposition result"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The Biot-Savart law, like Coulomb''s law, obeys the principle of superposition, meaning the total magnetic field at a point due to several current-carrying conductors is the vector sum of the fields produced by each conductor individually.", "explanation": "This statement is TRUE. The principle of superposition applies to both electric and magnetic fields. The total magnetic field at any point due to multiple current sources is obtained by taking the vector sum of the individual magnetic fields produced by each source. This is a fundamental property used extensively in calculating magnetic fields of complex current configurations.", "correct_answer": "A", "concept_tags": ["superposition-principle", "biot-savart-law", "vector-addition"], "payload": {"question_id": "cuet-phy-mag-biot-31", "subtopic": "Superposition of magnetic fields", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Superposition is valid for all electromagnetic fields in free space. Magnetic fields from different sources add vectorially.", "misconception": "Thinking superposition fails for magnetic fields"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside an ideal solenoid is uniform and parallel to the axis of the solenoid.", "explanation": "This is TRUE. By applying Ampere''s circuital law to an ideal (infinitely long) solenoid, the magnetic field inside is found to be B = μ₀nI, which is constant and does not depend on the position inside the solenoid. The field is directed along the axis of the solenoid, as determined by the right-hand rule. Outside the ideal solenoid, the field is zero.", "correct_answer": "A", "concept_tags": ["solenoid", "uniform-field", "ampere-law"], "payload": {"question_id": "cuet-phy-mag-biot-32", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The statement is a well-known result from Ampere''s law. The field B = μ₀nI is independent of position inside the solenoid and is directed along the axis.", "misconception": "Thinking the field varies inside a solenoid or is not axial"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field due to an infinitely long straight wire carrying current I varies inversely as the square of the perpendicular distance from the wire (B ∝ 1/d²).", "explanation": "This statement is FALSE. The magnetic field due to an infinitely long straight current-carrying wire is B = μ₀I/(2πd), which shows that B varies inversely as the first power of distance (B ∝ 1/d), not as the square of the distance. The inverse-square dependence (1/r²) appears in Coulomb''s law for a point charge, not in the magnetic field of an infinite wire.", "correct_answer": "B", "concept_tags": ["infinite-wire", "distance-dependence", "inverse-distance"], "payload": {"question_id": "cuet-phy-mag-biot-33", "subtopic": "Infinite straight wire", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Recall B = μ₀I/(2πd) for an infinite wire. The d is in the first power in the denominator, not squared.", "misconception": "Confusing the 1/r² in Biot-Savart law (for a point element) with the integrated result for an infinite wire"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field at a point on the axis of a current-carrying circular loop is always perpendicular to the axis of the loop.", "explanation": "This is FALSE. The magnetic field at any point on the axis of a current-carrying circular loop is directed along the axis of the loop (either towards or away from the loop depending on current direction), not perpendicular to it. By symmetry, the perpendicular components from opposite current elements cancel out, leaving only the axial component. The field is given by B = μ₀IR²/[2(R² + x²)^(3/2)] along the axis.", "correct_answer": "B", "concept_tags": ["circular-loop", "axial-field", "symmetry", "field-direction"], "payload": {"question_id": "cuet-phy-mag-biot-34", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The field on the axis is along the axis, not perpendicular to it. By symmetry, the perpendicular components cancel. Think of the right-hand thumb rule: curling fingers in the direction of current, the thumb points along the axis.", "misconception": "Confusing axial direction with perpendicular direction for on-axis field"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b08');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "A circular coil of radius 0.1 m carrying a current of 3.14 A has ________ turns if the magnetic field at its centre is 2 × 10⁻⁵ T. (Use μ₀ = 4π × 10⁻⁷ T·m/A and π = 3.14)", "explanation": "The magnetic field at the centre of a coil with N turns is B = μ₀NI/(2R). Solving for N: N = 2BR/(μ₀I) = 2 × (2 × 10⁻⁵) × 0.1 / (4π × 10⁻⁷ × 3.14) = (4 × 10⁻⁶) / (4 × 3.14 × 3.14 × 10⁻⁷) = (4 × 10⁻⁶) / (39.44 × 10⁻⁷) = (4 × 10⁻⁶) / (3.944 × 10⁻⁶) ≈ 1. Wait, let me recalculate: N = 2 × 2×10⁻⁵ × 0.1 / (4π × 10⁻⁷ × 3.14) = 4×10⁻⁶ / (4 × 3.14 × 10⁻⁷ × 3.14) = 4×10⁻⁶ / (3.944 × 10⁻⁶) ≈ 1. Actually: μ₀I = 4π × 10⁻⁷ × 3.14 = 4 × 3.14 × 3.14 × 10⁻⁷ = 39.44 × 10⁻⁷. 2BR = 2 × 2×10⁻⁵ × 0.1 = 4 × 10⁻⁶. N = 4×10⁻⁶ / 39.44×10⁻⁷ = 4×10⁻⁶ / 3.944×10⁻⁶ ≈ 1. So N = 1 turn. The answer is B (1 turn).", "correct_answer": "B", "concept_tags": ["circular-coil", "number-of-turns", "magnetic-field-centre"], "payload": {"question_id": "cuet-phy-mag-biot-35", "subtopic": "Magnetic field due to circular loop at centre", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2", "is_correct": false}, {"key": "B", "text": "1", "is_correct": true}, {"key": "C", "text": "5", "is_correct": false}, {"key": "D", "text": "10", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Substitute the values carefully. N = 2BR/(μ₀I). With the given numbers, N comes out to approximately 1.", "misconception": "Arithmetic error in calculation"}, {"option_key": "C", "hint": "This would give a much larger field at the centre. Check your powers of 10.", "misconception": "Error in handling powers of 10"}, {"option_key": "D", "hint": "10 turns would produce a field 10 times larger than what is given.", "misconception": "Forgetting to divide by the correct factor"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "If a circular coil of 200 turns and radius 0.05 m carries a current of 0.5 A, the magnetic field at its centre is _____ T. (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "For a flat coil of N turns, the magnetic field at the centre is B = μ₀NI/(2R). Substituting: B = (4π × 10⁻⁷ × 200 × 0.5)/(2 × 0.05) = (4π × 10⁻⁷ × 100)/0.1 = (4π × 10⁻⁵)/0.1 = 4π × 10⁻⁴ = 12.57 × 10⁻⁴ T ≈ 1.26 × 10⁻³ T.", "correct_answer": "C", "concept_tags": ["circular-coil", "multiple-turns", "magnetic-field-centre", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-biot-36", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 × 10⁻³", "is_correct": false}, {"key": "B", "text": "1.26 × 10⁻⁴", "is_correct": false}, {"key": "C", "text": "1.26 × 10⁻³", "is_correct": true}, {"key": "D", "text": "6.28 × 10⁻⁴", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6.28 × 10⁻³ is five times too large. Check if you used the correct radius: R = 0.05 m, not 0.01 m.", "misconception": "Using incorrect radius value"}, {"option_key": "B", "hint": "1.26 × 10⁻⁴ is off by a factor of 10. Recheck: μ₀NI = 4π × 10⁻⁷ × 200 × 0.5 = 4π × 10⁻⁵, and dividing by 2R = 0.1 gives 4π × 10⁻⁴ ≈ 1.26 × 10⁻³.", "misconception": "Power of 10 error"}, {"option_key": "D", "hint": "6.28 × 10⁻⁴ = 2π × 10⁻⁴, which suggests using N = 100 or I = 0.25. With the given values, B = 4π × 10⁻⁴ ≈ 1.26 × 10⁻³ T.", "misconception": "Halving one of the given quantities"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "An MRI (Magnetic Resonance Imaging) machine uses a large solenoid to produce a strong, uniform magnetic field for medical imaging. A particular MRI solenoid is 2 m long, has 10,000 turns, and produces a magnetic field of 1.5 T inside. What is the current flowing through the solenoid? (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "For a solenoid, B = μ₀nI, where n = N/L = 10000/2 = 5000 turns/m. Rearranging for current: I = B/(μ₀n) = 1.5/(4π × 10⁻⁷ × 5000) = 1.5/(2π × 10⁻³) = 1.5/(6.283 × 10⁻³) ≈ 238.7 A ≈ 239 A. This illustrates why MRI machines require superconducting coils to sustain such large currents without resistive heating.", "correct_answer": "D", "concept_tags": ["solenoid", "MRI-application", "ampere-law", "numerical-problem", "real-world"], "payload": {"question_id": "cuet-phy-mag-biot-37", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "23.9 A", "is_correct": false}, {"key": "B", "text": "119 A", "is_correct": false}, {"key": "C", "text": "477 A", "is_correct": false}, {"key": "D", "text": "239 A", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "23.9 A is ten times too small. Check n = N/L = 10000/2 = 5000 turns/m, not 50000. Then I = 1.5/(4π × 10⁻⁷ × 5000) ≈ 239 A.", "misconception": "Error in calculating turns per unit length"}, {"option_key": "B", "hint": "119 A is half the correct answer. This could result from using L = 1 m instead of 2 m (making n = 10000 instead of 5000), then dividing again incorrectly.", "misconception": "Using incorrect length or extra factor of 2"}, {"option_key": "C", "hint": "477 A is double the correct answer, suggesting n = N/L was calculated as 2500 instead of 5000, or an error in length. Use L = 2 m to get n = 5000.", "misconception": "Halving the turns per unit length"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "At what approximate distance along the x-axis from the origin does the net magnetic field become zero, given that both the straight wire and the circular loop produce fields in opposite directions along the positive x-axis? (Use μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "The magnetic field due to the straight wire at distance x on the x-axis is B_wire = μ₀I₁/(2πx) = μ₀(5)/(2πx). The field due to the circular loop on its axis at distance x is B_loop = μ₀I₂R²/(2(R² + x²)^(3/2)) = μ₀(2)(0.05)²/(2(0.0025 + x²)^(3/2)). Setting B_wire = B_loop and simplifying: 5/(2πx) = 2(0.0025)/(2(0.0025 + x²)^(3/2)). For x >> R (far field), B_loop ≈ μ₀(2)(0.0025)/(2x³). So 5/(2πx) = 0.0025/x³, giving x² = 0.0025 × 2π/5 = 0.00314, so x ≈ 0.056 m ≈ 0.06 m. Among the options, 0.06 m is closest.", "correct_answer": "B", "concept_tags": ["superposition", "null-point", "straight-wire", "circular-loop-axis"], "payload": {"question_id": "cuet-phy-mag-biot-38", "subtopic": "Superposition of magnetic fields", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "0.03 m", "is_correct": false}, {"key": "B", "text": "0.06 m", "is_correct": true}, {"key": "C", "text": "0.10 m", "is_correct": false}, {"key": "D", "text": "0.15 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "At 0.03 m (close to the loop radius), the loop field dominates and the far-field approximation is not valid. The null point is farther out.", "misconception": "Underestimating the distance where fields balance"}, {"option_key": "C", "hint": "At 0.10 m, the loop field drops as 1/x³ while the wire field drops as 1/x, so the wire field dominates and they cannot be equal here.", "misconception": "Overestimating the null-point distance"}, {"option_key": "D", "hint": "At such large distance, the loop field is negligible compared to the wire field. The null point must be closer.", "misconception": "Not recognizing the rapid decay of dipole fields"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps in the correct order for deriving the magnetic field at the centre of a circular current-carrying loop using Biot-Savart law.", "explanation": "The derivation proceeds as follows: (Step 2) Start by considering a small current element and applying Biot-Savart law. (Step 5) Recognise that the distance r from any element to the centre equals R. (Step 1) Note that dl is perpendicular to r̂ at the centre, so the cross product magnitude simplifies. (Step 4) Integrate over the full loop, substituting the simplified expressions. (Step 3) Evaluate the integral to obtain the final result B = μ₀I/(2R).", "correct_answer": "D", "concept_tags": ["biot-savart-derivation", "circular-loop", "integration"], "payload": {"question_id": "cuet-phy-mag-biot-39", "subtopic": "Magnetic field due to circular loop at centre", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "1 → 2 → 5 → 4 → 3", "is_correct": false}, {"key": "B", "text": "2 → 1 → 5 → 3 → 4", "is_correct": false}, {"key": "C", "text": "5 → 2 → 1 → 4 → 3", "is_correct": false}, {"key": "D", "text": "2 → 5 → 1 → 4 → 3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "You must first write the Biot-Savart law (step 2) before noting the perpendicularity (step 1).", "misconception": "Applying geometric simplification before stating the law"}, {"option_key": "B", "hint": "Integration (step 4) must come before the final result (step 3), and geometric observations (step 5) before cross-product simplification (step 1).", "misconception": "Jumbling the order of simplification and integration"}, {"option_key": "C", "hint": "You should state the Biot-Savart law (step 2) before identifying the constant distance (step 5), since the law defines what r represents.", "misconception": "Identifying geometric properties before stating the governing law"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following current-carrying configurations in order of increasing magnetic field strength at the specified point, from weakest to strongest. All carry the same current I and have the same characteristic dimension R.", "explanation": "The magnetic field at the centre of curvature of a circular arc subtending angle θ is B = μ₀Iθ/(4πR). For a quarter circle (θ = π/2): B = μ₀I/(8R). For a semicircle (θ = π): B = μ₀I/(4R). For a three-quarter arc (θ = 3π/2): B = 3μ₀I/(8R). For a full circle (θ = 2π): B = μ₀I/(2R). Ordering from weakest to strongest: quarter < semicircle < three-quarter < full circle, i.e., 1 → 3 → 4 → 2.", "correct_answer": "A", "concept_tags": ["circular-arc", "field-comparison", "proportionality-to-angle"], "payload": {"question_id": "cuet-phy-mag-biot-40", "subtopic": "Magnetic field at centre of arc/semicircle", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 → 3 → 4 → 2", "is_correct": true}, {"key": "B", "text": "2 → 4 → 3 → 1", "is_correct": false}, {"key": "C", "text": "1 → 3 → 2 → 4", "is_correct": false}, {"key": "D", "text": "3 → 1 → 4 → 2", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the reverse order (strongest to weakest). The question asks for weakest to strongest.", "misconception": "Reading the question as strongest to weakest"}, {"option_key": "C", "hint": "A full circle (2) has a larger field than a three-quarter arc (4), since it subtends a larger angle.", "misconception": "Thinking 3/4 arc produces a stronger field than a full loop"}, {"option_key": "D", "hint": "A quarter-circle (1) produces a weaker field than a semicircle (3), since π/2 < π.", "misconception": "Incorrectly ranking quarter-circle above semicircle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Ampere''s circuital law relates the line integral of magnetic field around a closed loop to:", "explanation": "Ampere''s circuital law states ∮B⃗·dl⃗ = μ₀I_enclosed. The line integral of the magnetic field B⃗ around any closed Amperian loop equals μ₀ times the net current enclosed by that loop.", "correct_answer": "A", "concept_tags": ["ampere-law-statement", "line-integral", "enclosed-current"], "payload": {"question_id": "cuet-phy-mag-ampere-01", "subtopic": "Ampere''s law statement", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀ times the net current enclosed by the loop", "is_correct": true}, {"key": "B", "text": "The total magnetic flux through the loop", "is_correct": false}, {"key": "C", "text": "The electric field inside the loop", "is_correct": false}, {"key": "D", "text": "The total current in the external circuit", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Magnetic flux is the surface integral ∫B⃗·dA⃗, not the line integral ∮B⃗·dl⃗.", "misconception": "Confusing line integral with surface integral"}, {"option_key": "C", "hint": "Ampere''s law deals with magnetic field B⃗, not electric field E⃗.", "misconception": "Mixing up electric and magnetic field laws"}, {"option_key": "D", "hint": "Only the current passing through the area bounded by the Amperian loop matters, not the total circuit current.", "misconception": "Using total circuit current instead of enclosed current"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of the line integral ∮B⃗·dl⃗ in Ampere''s circuital law is:", "explanation": "The line integral ∮B⃗·dl⃗ has the unit of B (Tesla) × l (metre) = T·m. Since T = kg·s⁻²·A⁻¹, the unit becomes kg·m·s⁻²·A⁻¹, which is the same as the unit of μ₀I (T·m/A × A = T·m).", "correct_answer": "B", "concept_tags": ["line-integral", "units", "ampere-law"], "payload": {"question_id": "cuet-phy-mag-ampere-02", "subtopic": "Line integral of B", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "Tesla", "is_correct": false}, {"key": "B", "text": "Tesla·metre", "is_correct": true}, {"key": "C", "text": "Tesla/metre", "is_correct": false}, {"key": "D", "text": "Weber", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Tesla is the unit of B alone. The line integral multiplies B by dl, adding a metre to the unit.", "misconception": "Forgetting the dl contribution in the integral"}, {"option_key": "C", "hint": "Tesla/metre would arise from dB/dl, not B·dl. Integration multiplies units, not divides.", "misconception": "Confusing differentiation with integration units"}, {"option_key": "D", "hint": "Weber (Wb) is the unit of magnetic flux Φ = ∫B⃗·dA⃗ (T·m²), not the line integral (T·m).", "misconception": "Confusing line integral with surface integral units"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "An Amperian loop is drawn in a region where no current passes through the loop. The value of ∮B⃗·dl⃗ for this loop is:", "explanation": "By Ampere''s circuital law, ∮B⃗·dl⃗ = μ₀I_enclosed. If no current threads through the Amperian loop, I_enclosed = 0, so ∮B⃗·dl⃗ = 0. Note that B⃗ itself need not be zero at every point on the loop; only the line integral around the closed loop is zero.", "correct_answer": "C", "concept_tags": ["amperian-loop", "zero-enclosed-current", "line-integral"], "payload": {"question_id": "cuet-phy-mag-ampere-03", "subtopic": "Amperian loop", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "μ₀", "is_correct": false}, {"key": "B", "text": "Infinity", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "Cannot be determined without knowing B⃗", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀ alone has no physical meaning here. ∮B⃗·dl⃗ = μ₀ × 0 = 0 when no current is enclosed.", "misconception": "Thinking μ₀ appears even with zero enclosed current"}, {"option_key": "B", "hint": "The line integral is always finite. With zero enclosed current it equals zero.", "misconception": "Misunderstanding the nature of the line integral"}, {"option_key": "D", "hint": "Ampere''s law directly gives the result: ∮B⃗·dl⃗ = μ₀I_enc = 0. No additional information about B⃗ is needed.", "misconception": "Not recognizing that the law gives a direct answer for the line integral"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Ampere''s circuital law is analogous to which law in electrostatics?", "explanation": "Ampere''s circuital law (∮B⃗·dl⃗ = μ₀I_enc) is the magnetic analogue of Gauss''s law in electrostatics (∮E⃗·dA⃗ = Q_enc/ε₀). Both relate a field integral to an enclosed source (current or charge) and are most useful in situations of high symmetry.", "correct_answer": "D", "concept_tags": ["ampere-law", "gauss-law", "analogy"], "payload": {"question_id": "cuet-phy-mag-ampere-04", "subtopic": "Comparison with Gauss''s law", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Coulomb''s law", "is_correct": false}, {"key": "B", "text": "Faraday''s law", "is_correct": false}, {"key": "C", "text": "Biot-Savart law", "is_correct": false}, {"key": "D", "text": "Gauss''s law", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s law gives force between charges. Its magnetic analogue is the Biot-Savart law, not Ampere''s law.", "misconception": "Confusing Coulomb''s law analogy with Gauss''s law analogy"}, {"option_key": "B", "hint": "Faraday''s law relates changing magnetic flux to induced EMF. It is not the electrostatic analogue of Ampere''s law.", "misconception": "Mixing electromagnetic induction with magnetostatics"}, {"option_key": "C", "hint": "Biot-Savart law is analogous to Coulomb''s law (both give field due to a source element). Ampere''s law is analogous to Gauss''s law.", "misconception": "Confusing Biot-Savart analogy with Ampere''s law analogy"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "For applying Ampere''s circuital law to find the magnetic field inside a long solenoid, the ideal Amperian loop is:", "explanation": "To exploit the symmetry of a solenoid, we choose a rectangular Amperian loop with one side inside the solenoid (parallel to the axis) and the opposite side outside where B ≈ 0. The two short sides are perpendicular to B, contributing zero. This gives B·L = μ₀nLI, hence B = μ₀nI.", "correct_answer": "B", "concept_tags": ["solenoid", "amperian-loop", "rectangular-loop"], "payload": {"question_id": "cuet-phy-mag-ampere-05", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "A circular loop concentric with the solenoid", "is_correct": false}, {"key": "B", "text": "A rectangular loop partially inside and partially outside the solenoid", "is_correct": true}, {"key": "C", "text": "A triangular loop inside the solenoid", "is_correct": false}, {"key": "D", "text": "A spherical surface enclosing the solenoid", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A circular loop would not exploit the translational symmetry along the solenoid axis. The field inside is uniform and axial, requiring a rectangular loop.", "misconception": "Using the wrong symmetry for the Amperian loop"}, {"option_key": "C", "hint": "A triangular loop offers no symmetry advantage. The rectangular loop aligns sides parallel and perpendicular to B⃗.", "misconception": "Arbitrary loop shape without symmetry consideration"}, {"option_key": "D", "hint": "A spherical surface is used in Gauss''s law (surface integral), not Ampere''s law (line integral).", "misconception": "Confusing Gauss''s law surface with Amperian loop"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field inside an ideal solenoid with n turns per unit length carrying current I is:", "explanation": "Using Ampere''s circuital law with a rectangular Amperian loop, the field inside an ideal (infinite) solenoid is B = μ₀nI. This field is uniform throughout the interior and directed along the axis of the solenoid.", "correct_answer": "A", "concept_tags": ["solenoid", "magnetic-field-formula", "ampere-law-application"], "payload": {"question_id": "cuet-phy-mag-ampere-06", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀nI", "is_correct": true}, {"key": "B", "text": "μ₀nI/2π", "is_correct": false}, {"key": "C", "text": "μ₀NI", "is_correct": false}, {"key": "D", "text": "μ₀I/2πr", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The 2π factor appears for an infinite straight wire, not a solenoid. Inside a solenoid B = μ₀nI with no 2π denominator.", "misconception": "Mixing solenoid formula with straight wire formula"}, {"option_key": "C", "hint": "N is the total number of turns. The correct formula uses n = N/L (turns per unit length), giving B = μ₀nI.", "misconception": "Using total turns N instead of turns per unit length n"}, {"option_key": "D", "hint": "This is the formula for the magnetic field around an infinite straight wire, not inside a solenoid.", "misconception": "Applying the wrong formula for the geometry"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A long straight wire carries a current of 5 A. Using Ampere''s circuital law, the magnetic field at a distance of 10 cm from the wire is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a long straight wire, choosing a circular Amperian loop of radius r = 0.1 m: ∮B⃗·dl⃗ = B(2πr) = μ₀I. So B = μ₀I/(2πr) = (4π × 10⁻⁷ × 5)/(2π × 0.1) = (20π × 10⁻⁷)/(0.2π) = 10⁻⁵ T = 10 μT.", "correct_answer": "C", "concept_tags": ["infinite-wire", "numerical", "ampere-law-application"], "payload": {"question_id": "cuet-phy-mag-ampere-07", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "1 × 10⁻⁶ T", "is_correct": false}, {"key": "B", "text": "1 × 10⁻⁴ T", "is_correct": false}, {"key": "C", "text": "1 × 10⁻⁵ T", "is_correct": true}, {"key": "D", "text": "2 × 10⁻⁵ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Check: (4π × 10⁻⁷ × 5)/(2π × 0.1) = 10⁻⁵ T, not 10⁻⁶ T.", "misconception": "Error in powers of ten during calculation"}, {"option_key": "B", "hint": "This is 10 times too large. Ensure you converted 10 cm to 0.1 m properly in the denominator.", "misconception": "Not converting cm to m"}, {"option_key": "D", "hint": "This would correspond to I = 10 A or r = 5 cm. With I = 5 A and r = 10 cm, B = 10⁻⁵ T.", "misconception": "Arithmetic error in the final calculation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of length 50 cm has 500 turns and carries a current of 2 A. The magnetic field inside the solenoid is approximately:", "explanation": "Number of turns per unit length n = N/L = 500/0.5 = 1000 turns/m. Using B = μ₀nI = 4π × 10⁻⁷ × 1000 × 2 = 8π × 10⁻⁴ ≈ 2.51 × 10⁻³ T ≈ 2.5 mT.", "correct_answer": "D", "concept_tags": ["solenoid", "numerical", "turns-per-unit-length"], "payload": {"question_id": "cuet-phy-mag-ampere-08", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "1.26 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "6.28 × 10⁻⁴ T", "is_correct": false}, {"key": "C", "text": "1.26 × 10⁻² T", "is_correct": false}, {"key": "D", "text": "2.51 × 10⁻³ T", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This would correspond to I = 1 A instead of 2 A. The correct value is 8π × 10⁻⁴ ≈ 2.51 × 10⁻³ T.", "misconception": "Forgetting to multiply by the current value"}, {"option_key": "B", "hint": "This is too small. Check n = 500/0.5 = 1000/m, then B = 4π × 10⁻⁷ × 1000 × 2 = 2.51 × 10⁻³ T.", "misconception": "Incorrectly calculating n by using length in cm"}, {"option_key": "C", "hint": "This is 10 times too large. Verify: 4π × 10⁻⁷ × 10³ × 2 = 8π × 10⁻⁴ ≈ 2.51 × 10⁻³ T.", "misconception": "Error in powers of ten"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a toroid with N total turns, mean radius R, and carrying current I, the magnetic field inside the toroid at the mean radius is:", "explanation": "For a toroid, using a circular Amperian loop of radius R inside the toroid: ∮B⃗·dl⃗ = B(2πR) = μ₀NI. Therefore B = μ₀NI/(2πR). Unlike a solenoid, the field inside a toroid depends on the radial position.", "correct_answer": "B", "concept_tags": ["toroid", "magnetic-field-formula", "ampere-law-application"], "payload": {"question_id": "cuet-phy-mag-ampere-09", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀NI", "is_correct": false}, {"key": "B", "text": "μ₀NI/(2πR)", "is_correct": true}, {"key": "C", "text": "μ₀nI (where n = N/2πR)", "is_correct": false}, {"key": "D", "text": "Both B and C", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This would be the result if 2πR were absent. The Amperian loop has circumference 2πR, so B = μ₀NI/(2πR).", "misconception": "Forgetting the loop circumference factor"}, {"option_key": "C", "hint": "While n = N/(2πR) gives the same numerical result, the standard form is B = μ₀NI/(2πR). Option C writes the formula differently but is not wrong in value — however option D says ''Both B and C'' which makes C alone incorrect as an answer.", "misconception": "Not recognizing the standard form of the toroid formula"}, {"option_key": "D", "hint": "While B and C give the same numerical value, the question asks for the field expression in standard form. B = μ₀NI/(2πR) is the direct result from Ampere''s law. Since C is just a rewrite, the primary answer is B.", "misconception": "Thinking both equivalent forms should be the answer when only the standard form is asked"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A circular Amperian loop of radius r is drawn concentric with a long straight wire carrying current I. If the radius is doubled to 2r, the value of ∮B⃗·dl⃗ will:", "explanation": "By Ampere''s law, ∮B⃗·dl⃗ = μ₀I_enclosed. The enclosed current remains I regardless of the loop radius (as long as the wire passes through it). Therefore, the line integral remains unchanged at μ₀I even when the radius is doubled.", "correct_answer": "A", "concept_tags": ["amperian-loop", "enclosed-current", "line-integral-independence"], "payload": {"question_id": "cuet-phy-mag-ampere-10", "subtopic": "Line integral of B", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Remain the same", "is_correct": true}, {"key": "B", "text": "Become half", "is_correct": false}, {"key": "C", "text": "Become double", "is_correct": false}, {"key": "D", "text": "Become four times", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "While B becomes half (B ∝ 1/r), the circumference doubles (2πr → 4πr). The product B × 2πr = μ₀I remains unchanged.", "misconception": "Thinking the line integral changes because B changes"}, {"option_key": "C", "hint": "The line integral depends only on I_enclosed, not on the loop size. ∮B⃗·dl⃗ = μ₀I regardless of r.", "misconception": "Confusing the integral with circumference alone"}, {"option_key": "D", "hint": "The line integral is independent of the loop radius. It equals μ₀I for any loop enclosing the wire.", "misconception": "Incorrectly applying area dependence to line integral"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field outside an ideal infinite solenoid is:", "explanation": "Using Ampere''s circuital law with a rectangular loop entirely outside the solenoid: since no net current is enclosed (currents on both sides cancel), ∮B⃗·dl⃗ = 0, implying B_outside = 0. This is a key result — the field of an ideal infinite solenoid is entirely confined to its interior.", "correct_answer": "C", "concept_tags": ["solenoid", "field-outside", "zero-field"], "payload": {"question_id": "cuet-phy-mag-ampere-11", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀nI", "is_correct": false}, {"key": "B", "text": "μ₀nI/2", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "Depends on the distance from the solenoid", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀nI is the field inside the solenoid. Outside an ideal infinite solenoid, the field is zero.", "misconception": "Confusing inside and outside fields"}, {"option_key": "B", "hint": "There is no half-value region. The field is μ₀nI inside and zero outside.", "misconception": "Incorrectly averaging fields"}, {"option_key": "D", "hint": "For an ideal infinite solenoid, the external field is exactly zero everywhere, independent of distance.", "misconception": "Treating the solenoid like a dipole with distance-dependent field"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two long parallel wires separated by distance d carry currents I₁ and I₂ in the same direction. An Amperian loop enclosing both wires will give ∮B⃗·dl⃗ equal to:", "explanation": "By Ampere''s circuital law, ∮B⃗·dl⃗ = μ₀(I_enclosed). When both wires carry currents in the same direction and both are enclosed by the Amperian loop, I_enclosed = I₁ + I₂. Therefore ∮B⃗·dl⃗ = μ₀(I₁ + I₂).", "correct_answer": "D", "concept_tags": ["parallel-wires", "enclosed-current", "superposition"], "payload": {"question_id": "cuet-phy-mag-ampere-12", "subtopic": "Line integral of B", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀(I₁ − I₂)", "is_correct": false}, {"key": "B", "text": "μ₀I₁", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "μ₀(I₁ + I₂)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Subtraction would apply if the currents were in opposite directions. For same-direction currents, the enclosed current is I₁ + I₂.", "misconception": "Confusing same-direction with opposite-direction current addition"}, {"option_key": "B", "hint": "Both wires are enclosed by the loop, so both currents contribute. I_enclosed = I₁ + I₂, not just I₁.", "misconception": "Considering only one wire''s contribution"}, {"option_key": "C", "hint": "Zero would result if the currents cancelled (equal and opposite). Same-direction currents add up.", "misconception": "Thinking currents always cancel in a multi-wire setup"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A toroid has 1000 turns, mean radius 20 cm, and carries a current of 3 A. The magnetic field at the centre of the cross-section of the toroid is approximately:", "explanation": "For a toroid, B = μ₀NI/(2πR) = (4π × 10⁻⁷ × 1000 × 3)/(2π × 0.2) = (12π × 10⁻⁴)/(0.4π) = 12 × 10⁻⁴/0.4 = 30 × 10⁻⁴ = 3 × 10⁻³ T = 3 mT.", "correct_answer": "B", "concept_tags": ["toroid", "numerical", "ampere-law-application"], "payload": {"question_id": "cuet-phy-mag-ampere-13", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "1.5 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "3 × 10⁻³ T", "is_correct": true}, {"key": "C", "text": "6 × 10⁻³ T", "is_correct": false}, {"key": "D", "text": "3 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is half the correct value. Check: μ₀NI/(2πR) = (4π × 10⁻⁷ × 3000)/(2π × 0.2) = 3 × 10⁻³ T.", "misconception": "Extra factor of 2 in the denominator"}, {"option_key": "C", "hint": "This is double the correct value. Ensure R = 20 cm = 0.2 m is used, not 0.1 m.", "misconception": "Using radius instead of diameter or vice versa"}, {"option_key": "D", "hint": "This is off by a factor of 10. Recheck the calculation carefully.", "misconception": "Error in powers of ten"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Ampere''s circuital law in its original form is not valid when:", "explanation": "The original Ampere''s circuital law (∮B⃗·dl⃗ = μ₀I_enc) is valid only for steady (time-independent) currents. When electric fields change with time, a displacement current term μ₀ε₀(dΦ_E/dt) must be added (Maxwell''s modification). This is a key limitation of the original law.", "correct_answer": "D", "concept_tags": ["limitations", "displacement-current", "maxwell-modification"], "payload": {"question_id": "cuet-phy-mag-ampere-14", "subtopic": "Limitations", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "The current is very large", "is_correct": false}, {"key": "B", "text": "The Amperian loop is very small", "is_correct": false}, {"key": "C", "text": "The wire is curved", "is_correct": false}, {"key": "D", "text": "The electric field is changing with time", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Ampere''s law has no restriction on the magnitude of current. It works for any steady current, large or small.", "misconception": "Thinking the law breaks down for large currents"}, {"option_key": "B", "hint": "The law holds for Amperian loops of any size. The loop size affects what current is enclosed, not the law''s validity.", "misconception": "Confusing loop size with validity"}, {"option_key": "C", "hint": "Ampere''s law applies to any current configuration, straight or curved, as long as the current is steady.", "misconception": "Thinking the law requires straight wires"}]}}]'::jsonb, 'deploy-2026-03-05-b08');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A long cylindrical conductor of radius R carries a uniformly distributed current I. Using Ampere''s circuital law, the magnetic field at a distance r (r < R) from the axis is:", "explanation": "For r < R, the Amperian loop of radius r encloses a fraction of the total current: I_enc = I(πr²/πR²) = Ir²/R². By Ampere''s law: B(2πr) = μ₀Ir²/R², giving B = μ₀Ir/(2πR²). The field increases linearly with r inside the conductor.", "correct_answer": "A", "concept_tags": ["cylindrical-conductor", "internal-field", "linear-variation"], "payload": {"question_id": "cuet-phy-mag-ampere-15", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀Ir/(2πR²)", "is_correct": true}, {"key": "B", "text": "μ₀I/(2πr)", "is_correct": false}, {"key": "C", "text": "μ₀IR/(2πr²)", "is_correct": false}, {"key": "D", "text": "μ₀I/(2πR)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This formula applies outside the conductor (r > R), where all current I is enclosed. Inside, only a fraction r²/R² of I is enclosed.", "misconception": "Using the external field formula for the interior region"}, {"option_key": "C", "hint": "This has incorrect powers of r and R. The enclosed current is proportional to r², and dividing by 2πr gives B ∝ r, not R/r².", "misconception": "Inverting the r and R dependence"}, {"option_key": "D", "hint": "This gives the field at the surface (r = R) and is a constant, but inside the conductor B varies linearly with r.", "misconception": "Taking r = R instead of keeping r as variable"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A coaxial cable has an inner conductor of radius a carrying current I and an outer conductor (hollow cylinder) of inner radius b and outer radius c carrying current I in the opposite direction. The magnetic field in the region a < r < b is:", "explanation": "In the region a < r < b (between the conductors), the Amperian loop of radius r encloses only the inner conductor''s current I. By Ampere''s law: B(2πr) = μ₀I, giving B = μ₀I/(2πr). The outer conductor''s current doesn''t contribute since it''s outside the Amperian loop.", "correct_answer": "C", "concept_tags": ["coaxial-cable", "ampere-law-application", "enclosed-current"], "payload": {"question_id": "cuet-phy-mag-ampere-16", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "μ₀I/(2πa)", "is_correct": false}, {"key": "C", "text": "μ₀I/(2πr)", "is_correct": true}, {"key": "D", "text": "μ₀2I/(2πr)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The field is zero only outside both conductors (r > c) where the net enclosed current is zero. Between the conductors, I_enc = I.", "misconception": "Thinking the field cancels everywhere due to opposite currents"}, {"option_key": "B", "hint": "The field depends on the distance r from the axis, not the inner conductor radius a. B varies as 1/r in this region.", "misconception": "Using the conductor radius instead of the field point distance"}, {"option_key": "D", "hint": "Only the inner conductor''s current I is enclosed, not 2I. The outer current lies outside the Amperian loop for a < r < b.", "misconception": "Adding both currents instead of using only the enclosed one"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An infinite hollow cylindrical conductor has inner radius a and outer radius b, carrying a uniformly distributed current I. The magnetic field at a distance r where a < r < b from the axis is:", "explanation": "The current is distributed in the annular region from a to b. For a < r < b, the enclosed current is I_enc = I × (r² − a²)/(b² − a²). By Ampere''s law: B(2πr) = μ₀I(r² − a²)/(b² − a²), giving B = μ₀I(r² − a²)/[2πr(b² − a²)].", "correct_answer": "D", "concept_tags": ["hollow-conductor", "partial-enclosed-current", "ampere-law"], "payload": {"question_id": "cuet-phy-mag-ampere-17", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "μ₀Ir/(2πb²)", "is_correct": false}, {"key": "B", "text": "μ₀I/(2πr)", "is_correct": false}, {"key": "C", "text": "μ₀I(r² − a²)/(2πr·b²)", "is_correct": false}, {"key": "D", "text": "μ₀I(r² − a²)/[2πr(b² − a²)]", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This formula is for a solid conductor of radius b. A hollow conductor has no current for r < a, so the area ratio is (r² − a²)/(b² − a²), not r²/b².", "misconception": "Treating hollow conductor as solid"}, {"option_key": "B", "hint": "This would be correct only outside the conductor (r > b). Inside the conductor wall, only a fraction of I is enclosed.", "misconception": "Using the total current formula inside the conductor"}, {"option_key": "C", "hint": "The denominator should be (b² − a²), not just b². The current-carrying area is π(b² − a²), not πb².", "misconception": "Incorrect area of the annular cross-section"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A solenoid has 2000 turns, length 40 cm, and carries 3 A. If it is bent into a toroid of mean radius R such that all turns are uniformly distributed, the magnetic field inside the toroid compared to that inside the original solenoid will be:", "explanation": "For the solenoid: B_sol = μ₀nI = μ₀(2000/0.4)(3) = μ₀(5000)(3) = 15000μ₀. For the toroid: B_tor = μ₀NI/(2πR). The length of the solenoid = circumference of toroid: 0.4 m = 2πR, so R = 0.4/(2π). Then B_tor = μ₀(2000)(3)/(2π × 0.4/(2π)) = μ₀ × 6000/0.4 = 15000μ₀. The field is the same because n = N/(2πR) and the solenoid length equals 2πR.", "correct_answer": "B", "concept_tags": ["solenoid-toroid-comparison", "conceptual", "ampere-law"], "payload": {"question_id": "cuet-phy-mag-ampere-18", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "Greater in the toroid", "is_correct": false}, {"key": "B", "text": "The same at the mean radius", "is_correct": true}, {"key": "C", "text": "Less in the toroid", "is_correct": false}, {"key": "D", "text": "Cannot be compared without knowing R", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since the solenoid length becomes 2πR, n = N/L is the same as N/(2πR), and B = μ₀nI is identical.", "misconception": "Thinking bending concentrates the field"}, {"option_key": "C", "hint": "The toroid doesn''t weaken the field. At the mean radius the field equals the solenoid field.", "misconception": "Thinking bending reduces field due to geometry change"}, {"option_key": "D", "hint": "R is determined by the solenoid length: 2πR = L = 0.4 m. No additional information is needed.", "misconception": "Not recognizing that the solenoid length fixes the toroid radius"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A long straight wire carries current I. An Amperian loop in the form of a square of side ''a'' is placed such that the wire passes through the centre of the square, perpendicular to its plane. The value of ∮B⃗·dl⃗ around this square loop is:", "explanation": "Ampere''s circuital law states ∮B⃗·dl⃗ = μ₀I_enclosed. The shape of the Amperian loop does not matter — it can be circular, square, or any closed curve. Since the wire carrying current I passes through the loop, I_enclosed = I, and ∮B⃗·dl⃗ = μ₀I regardless of the square shape.", "correct_answer": "C", "concept_tags": ["amperian-loop-shape", "line-integral", "loop-independence"], "payload": {"question_id": "cuet-phy-mag-ampere-19", "subtopic": "Amperian loop", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "μ₀I × 4a", "is_correct": false}, {"key": "B", "text": "μ₀I/(4a)", "is_correct": false}, {"key": "C", "text": "μ₀I", "is_correct": true}, {"key": "D", "text": "Cannot be determined as B is not constant on the square", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The perimeter 4a does not appear in the result. Ampere''s law gives ∮B⃗·dl⃗ = μ₀I regardless of loop shape or size.", "misconception": "Multiplying μ₀I by the perimeter"}, {"option_key": "B", "hint": "Division by the side length has no basis. The line integral equals μ₀I independent of loop dimensions.", "misconception": "Incorrectly dividing by a geometric factor"}, {"option_key": "D", "hint": "While B⃗ is not constant on the square loop (making it harder to find B), the line integral ∮B⃗·dl⃗ is still determined by Ampere''s law as μ₀I.", "misconception": "Confusing the ability to find B at each point with the value of the integral"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Inside a toroid of rectangular cross-section with inner radius a, outer radius b, N turns, and current I, the magnetic field varies as:", "explanation": "For a toroid, applying Ampere''s law with a circular loop of radius r (a < r < b): B(2πr) = μ₀NI, so B = μ₀NI/(2πr). The field varies inversely with r. It is strongest at the inner radius a and weakest at the outer radius b. The field is not uniform across the cross-section.", "correct_answer": "A", "concept_tags": ["toroid", "field-variation", "non-uniform-field"], "payload": {"question_id": "cuet-phy-mag-ampere-20", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "B ∝ 1/r, where r is the distance from the centre of the toroid", "is_correct": true}, {"key": "B", "text": "B is uniform throughout the cross-section", "is_correct": false}, {"key": "C", "text": "B ∝ r", "is_correct": false}, {"key": "D", "text": "B ∝ 1/r²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Unlike an ideal solenoid, the toroid''s field is not uniform. B = μ₀NI/(2πr) varies with the radial position r.", "misconception": "Treating toroid field as uniform like a solenoid"}, {"option_key": "C", "hint": "B ∝ r applies inside a solid conductor. In a toroid, all N turns are enclosed for any loop between a and b, giving B ∝ 1/r.", "misconception": "Confusing toroid with solid conductor field variation"}, {"option_key": "D", "hint": "The 1/r² dependence applies to point sources (dipoles at large distances). The line integral geometry gives B ∝ 1/r for a toroid.", "misconception": "Using inverse-square law instead of Ampere''s law result"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "In the diagram, a long straight wire carrying current I is shown with four Amperian loops (P, Q, R, S) of different shapes drawn around it. For which loop(s) does Ampere''s circuital law give ∮B⃗·dl⃗ = μ₀I?", "explanation": "Ampere''s circuital law states ∮B⃗·dl⃗ = μ₀I_enclosed for any closed loop. The result depends only on whether the current passes through the loop, not on the loop''s shape. All four loops (P: circle, Q: square, R: ellipse, S: irregular shape) enclose the wire, so each gives ∮B⃗·dl⃗ = μ₀I.", "correct_answer": "D", "concept_tags": ["amperian-loop", "loop-shape-independence", "line-integral"], "payload": {"question_id": "cuet-phy-mag-ampere-21", "subtopic": "Amperian loop", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Only P (circular loop)", "is_correct": false}, {"key": "B", "text": "Only P and Q", "is_correct": false}, {"key": "C", "text": "Only P, Q, and R", "is_correct": false}, {"key": "D", "text": "All four loops P, Q, R, and S", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A circular loop makes B constant on the loop (simplifying calculation of B), but the line integral μ₀I is the same for any shape.", "misconception": "Thinking only circular loops give the correct integral"}, {"option_key": "B", "hint": "The result ∮B⃗·dl⃗ = μ₀I holds for all closed loops enclosing the wire, regardless of shape.", "misconception": "Restricting validity to regular geometric shapes"}, {"option_key": "C", "hint": "Even the irregular loop S gives the same result. Ampere''s law places no restriction on loop shape.", "misconception": "Excluding irregular shapes from Ampere''s law"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows three long parallel wires carrying currents: wire 1 (3 A, into the page), wire 2 (5 A, out of the page), and wire 3 (2 A, into the page). An Amperian loop encloses only wires 1 and 2. What is ∮B⃗·dl⃗ for this loop? (Take current out of page as positive.)", "explanation": "The Amperian loop encloses wire 1 (3 A into page = −3 A) and wire 2 (5 A out of page = +5 A). Net enclosed current = −3 + 5 = +2 A. Wire 3 is outside the loop and does not contribute. ∮B⃗·dl⃗ = μ₀ × 2 = 2μ₀ = 2 × 4π × 10⁻⁷ ≈ 8π × 10⁻⁷ T·m ≈ 2.51 × 10⁻⁶ T·m.", "correct_answer": "B", "concept_tags": ["multiple-wires", "enclosed-current", "sign-convention"], "payload": {"question_id": "cuet-phy-mag-ampere-22", "subtopic": "Line integral of B", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀ × 6 T·m", "is_correct": false}, {"key": "B", "text": "μ₀ × 2 T·m", "is_correct": true}, {"key": "C", "text": "μ₀ × 8 T·m", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This would be the sum of magnitudes (3 + 5 − 2). Only wires 1 and 2 are enclosed, and their currents must be added with proper signs: −3 + 5 = 2.", "misconception": "Adding all three wire currents or ignoring signs"}, {"option_key": "C", "hint": "This incorrectly adds magnitudes (3 + 5 = 8) without considering direction. Current into the page is negative: −3 + 5 = 2.", "misconception": "Not using sign convention for current direction"}, {"option_key": "D", "hint": "Zero would require equal currents in opposite directions inside the loop. Here I_enc = −3 + 5 = +2 A ≠ 0.", "misconception": "Thinking opposite currents always cancel"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows the cross-section of a solenoid with a rectangular Amperian loop ABCD. Side AB (length L) is inside the solenoid parallel to its axis, side CD is outside, and sides BC and DA are perpendicular to the axis. If the solenoid has n turns per unit length and carries current I, what is the contribution of side CD to the line integral?", "explanation": "Outside an ideal infinite solenoid, the magnetic field B = 0. Since B = 0 along side CD (which is outside the solenoid), the contribution of CD to ∮B⃗·dl⃗ is ∫B⃗·dl⃗ = 0. The entire contribution comes from side AB (inside), where B·L = μ₀nLI. Sides BC and DA contribute zero because B is perpendicular to dl along those sides.", "correct_answer": "C", "concept_tags": ["solenoid", "rectangular-loop", "outside-field-zero"], "payload": {"question_id": "cuet-phy-mag-ampere-23", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀nLI", "is_correct": false}, {"key": "B", "text": "μ₀nLI/2", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "−μ₀nLI", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀nLI is the contribution from side AB (inside the solenoid). Side CD is outside where B = 0.", "misconception": "Confusing inside and outside contributions"}, {"option_key": "B", "hint": "There is no half-contribution. Outside the solenoid B = 0, so the integral along CD is exactly zero.", "misconception": "Splitting the total integral equally between AB and CD"}, {"option_key": "D", "hint": "A negative contribution would require a non-zero B along CD in the opposite direction. Since B = 0 outside, the contribution is zero, not negative.", "misconception": "Assuming the outside field is negative of the inside field"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The diagram shows the cross-section of a thick cylindrical conductor of radius R carrying total current I uniformly distributed. The graph that correctly represents the variation of magnetic field B with distance r from the axis is:", "explanation": "Inside the conductor (r < R): B = μ₀Ir/(2πR²), so B increases linearly with r. At the surface (r = R): B = μ₀I/(2πR), maximum value. Outside (r > R): B = μ₀I/(2πr), so B decreases as 1/r. The graph shows a linear rise to r = R followed by a hyperbolic decrease.", "correct_answer": "A", "concept_tags": ["thick-conductor", "field-variation", "graphical-analysis"], "payload": {"question_id": "cuet-phy-mag-ampere-24", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "Graph A: B rises linearly for r < R and falls as 1/r for r > R", "is_correct": true}, {"key": "B", "text": "Graph B: B is constant for r < R and falls as 1/r for r > R", "is_correct": false}, {"key": "C", "text": "Graph C: B falls as 1/r throughout", "is_correct": false}, {"key": "D", "text": "Graph D: B rises linearly throughout", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Constant B for r < R describes the field inside a solenoid, not a solid conductor. Inside a conductor, B ∝ r (linear increase).", "misconception": "Confusing solid conductor with solenoid field profile"}, {"option_key": "C", "hint": "B ∝ 1/r applies only outside (r > R). At r = 0, B = 0 (by symmetry), so the field must increase from zero.", "misconception": "Ignoring the internal field variation"}, {"option_key": "D", "hint": "Linear increase applies only inside (r < R). Outside, the enclosed current is constant at I, so B ∝ 1/r (decreasing).", "misconception": "Not recognizing the change in behavior at r = R"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "easy", "question_text": "Assertion (A): Ampere''s circuital law can be used to easily find the magnetic field of an infinite straight current-carrying wire.\nReason (R): The magnetic field of an infinite straight wire has cylindrical symmetry, making B constant on a circular Amperian loop.", "explanation": "Both A and R are true. The cylindrical symmetry of the infinite wire ensures that B is constant in magnitude and tangential on any coaxial circular loop. This makes the integral ∮B⃗·dl⃗ = B(2πr) trivially solvable, which is exactly why Ampere''s law is useful here. R correctly explains A.", "correct_answer": "A", "concept_tags": ["assertion-reasoning", "symmetry", "infinite-wire"], "payload": {"question_id": "cuet-phy-mag-ampere-25", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains why Ampere''s law is easy to apply: cylindrical symmetry makes B constant on the loop, enabling simple integration.", "misconception": "Not connecting symmetry to ease of application"}, {"option_key": "C", "hint": "The reason is true — cylindrical symmetry does make B constant on circular loops concentric with the wire.", "misconception": "Denying the cylindrical symmetry of the wire''s field"}, {"option_key": "D", "hint": "The assertion is true — Ampere''s law is indeed a standard and easy method for finding B around an infinite wire.", "misconception": "Thinking Ampere''s law cannot be applied to find B of a straight wire"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The magnetic field at any point inside an ideal toroid in the empty space (not in the windings) is zero.\nReason (R): Ampere''s circuital law gives ∮B⃗·dl⃗ = 0 when the Amperian loop does not enclose any current.", "explanation": "A is false — the magnetic field inside a toroid (in the region of the windings, between the inner and outer radius) is non-zero: B = μ₀NI/(2πr). The field is zero only in the central hollow region (r < inner radius) and outside (r > outer radius). R is true — Ampere''s law does give zero when no current is enclosed. Since A is false and R is true, the answer is D.", "correct_answer": "D", "concept_tags": ["assertion-reasoning", "toroid", "field-regions"], "payload": {"question_id": "cuet-phy-mag-ampere-26", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The assertion is incorrectly stated. Inside the toroid (within the windings region), B ≠ 0. The field is zero only in the central hollow and outside.", "misconception": "Confusing the central hollow of the toroid with the winding region"}, {"option_key": "B", "hint": "Since A is false (field inside the winding region is non-zero), this option is incorrect.", "misconception": "Not correctly identifying the regions of a toroid"}, {"option_key": "C", "hint": "The assertion is false (as explained above), and the reason is true (Ampere''s law indeed gives zero for loops with no enclosed current).", "misconception": "Incorrectly evaluating the truth of A and R"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Ampere''s circuital law is valid for all closed loops, regardless of their shape.\nReason (R): The magnetic field B⃗ is always constant in magnitude on any Amperian loop.", "explanation": "A is true — Ampere''s law ∮B⃗·dl⃗ = μ₀I_enc holds for any closed loop of any shape. R is false — B is constant only on loops with appropriate symmetry (e.g., circular loop around a straight wire). For an arbitrary shaped loop, B varies along the loop. Since A is true and R is false, the answer is C.", "correct_answer": "C", "concept_tags": ["assertion-reasoning", "loop-shape", "field-constancy"], "payload": {"question_id": "cuet-phy-mag-ampere-27", "subtopic": "Amperian loop", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": true}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R is false. B is not constant on every Amperian loop — only on those with special symmetry (like circular loops around a straight wire).", "misconception": "Thinking B must be constant on any Amperian loop"}, {"option_key": "B", "hint": "R is false, so this option is ruled out. B varies along irregular-shaped loops.", "misconception": "Not recognizing that B varies on non-symmetric loops"}, {"option_key": "D", "hint": "A is true — Ampere''s law holds for any closed loop. The law is general; only practical computation of B requires symmetry.", "misconception": "Confusing the validity of the law with its computational ease"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Ampere''s circuital law in its original form fails to explain the continuity of current between the plates of a charging capacitor.\nReason (R): Between the capacitor plates, the conduction current is zero but a changing electric field exists, which is not accounted for in the original Ampere''s law.", "explanation": "Both A and R are true, and R correctly explains A. When a capacitor is charging, the conduction current flows in the wire but there is no conduction current between the plates. The original Ampere''s law gives contradictory results depending on the surface chosen for the Amperian loop. Maxwell resolved this by introducing displacement current (ε₀dΦ_E/dt) to account for the changing electric field between the plates.", "correct_answer": "A", "concept_tags": ["assertion-reasoning", "displacement-current", "limitations", "maxwell-modification"], "payload": {"question_id": "cuet-phy-mag-ampere-28", "subtopic": "Limitations", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains why A is true — the failure is precisely because the changing E field (displacement current) is not in the original law.", "misconception": "Not connecting the missing displacement current term to the failure"}, {"option_key": "C", "hint": "R is true — between the plates there is indeed no conduction current but a changing E field, and the original law ignores this.", "misconception": "Thinking conduction current flows between capacitor plates"}, {"option_key": "D", "hint": "A is true — the original Ampere''s law gives inconsistent results for the charging capacitor, which is a well-known limitation.", "misconception": "Denying the limitation of the original Ampere''s law"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following current configurations (Column I) with the magnetic field expressions obtained using Ampere''s circuital law (Column II):", "explanation": "1→Q: For an infinite straight wire, B = μ₀I/(2πr). 2→R: Inside a solenoid, B = μ₀nI (uniform). 3→P: Inside a toroid at radius r, B = μ₀NI/(2πr). 4→S: Outside an ideal solenoid, B = 0.", "correct_answer": "C", "concept_tags": ["matching", "field-formulas", "configurations"], "payload": {"question_id": "cuet-phy-mag-ampere-29", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "1→P, 2→R, 3→Q, 4→S", "is_correct": false}, {"key": "B", "text": "1→R, 2→Q, 3→P, 4→S", "is_correct": false}, {"key": "C", "text": "1→Q, 2→R, 3→P, 4→S", "is_correct": true}, {"key": "D", "text": "1→Q, 2→S, 3→P, 4→R", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Item 1 (infinite wire) gives B = μ₀I/(2πr) = Q, not P. P has N (total turns) in the formula, which is for a toroid.", "misconception": "Confusing the wire formula with the toroid formula"}, {"option_key": "B", "hint": "Item 1 (infinite wire) gives B = μ₀I/(2πr) = Q, and item 2 (solenoid) gives B = μ₀nI = R. This option swaps them.", "misconception": "Swapping solenoid and wire expressions"}, {"option_key": "D", "hint": "Item 2 (inside solenoid) has B = μ₀nI ≠ 0. The field is zero only outside the solenoid (item 4).", "misconception": "Placing zero field inside the solenoid instead of outside"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following Amperian loop regions for a solid cylindrical conductor of radius R carrying current I (Column I) with the corresponding magnetic field behaviour (Column II):", "explanation": "1→R: At r = 0 (on the axis), by symmetry B = 0. 2→P: For r < R, B = μ₀Ir/(2πR²) ∝ r (linear increase). 3→S: At r = R, B = μ₀I/(2πR), maximum value. 4→Q: For r > R, B = μ₀I/(2πr) ∝ 1/r (hyperbolic decrease).", "correct_answer": "D", "concept_tags": ["matching", "cylindrical-conductor", "field-regions"], "payload": {"question_id": "cuet-phy-mag-ampere-30", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "1→R, 2→Q, 3→S, 4→P", "is_correct": false}, {"key": "B", "text": "1→P, 2→R, 3→S, 4→Q", "is_correct": false}, {"key": "C", "text": "1→R, 2→P, 3→Q, 4→S", "is_correct": false}, {"key": "D", "text": "1→R, 2→P, 3→S, 4→Q", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Inside the conductor (item 2), B increases linearly (P), not decreases as 1/r (Q). The 1/r decrease is for r > R.", "misconception": "Swapping internal and external field behaviors"}, {"option_key": "B", "hint": "At r = 0, B = 0 (R), not linear increase (P). The field starts at zero on the axis by symmetry.", "misconception": "Not recognizing zero field on the axis"}, {"option_key": "C", "hint": "At r = R, B is maximum (S), not decreasing as 1/r (Q). The transition from linear increase to 1/r decrease occurs at the surface.", "misconception": "Misidentifying the surface as a region of decrease"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The value of ∮B⃗·dl⃗ in Ampere''s circuital law depends on the shape of the Amperian loop.", "explanation": "This statement is FALSE. Ampere''s circuital law states ∮B⃗·dl⃗ = μ₀I_enclosed. The value of the line integral depends only on the net current enclosed by the loop, not on its shape. Whether the loop is circular, square, elliptical, or irregular, the integral is the same as long as the same currents are enclosed.", "correct_answer": "B", "concept_tags": ["true-false", "loop-shape-independence", "line-integral"], "payload": {"question_id": "cuet-phy-mag-ampere-31", "subtopic": "Line integral of B", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The line integral ∮B⃗·dl⃗ equals μ₀I_enclosed, which depends only on the enclosed current, not the loop shape. While B⃗ may vary along the loop, the integral is shape-independent.", "misconception": "Confusing the value of B at points on the loop with the total line integral"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside an ideal solenoid is uniform and independent of the position inside the solenoid.", "explanation": "This statement is TRUE. For an ideal (infinite) solenoid, Ampere''s circuital law gives B = μ₀nI everywhere inside. The field does not depend on the radial position or the distance from either end (for an infinite solenoid). The field is uniform, directed along the axis, and has the same magnitude at all interior points.", "correct_answer": "A", "concept_tags": ["true-false", "solenoid", "uniform-field"], "payload": {"question_id": "cuet-phy-mag-ampere-32", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "For an ideal infinite solenoid, B = μ₀nI is indeed constant throughout the interior. The field is uniform and does not vary with position inside.", "misconception": "Thinking the solenoid field varies radially like a toroid"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "If ∮B⃗·dl⃗ = 0 for a closed Amperian loop, then the magnetic field B⃗ must be zero at every point on the loop.", "explanation": "This statement is FALSE. ∮B⃗·dl⃗ = 0 means the net enclosed current is zero, but this does not require B⃗ = 0 at every point. For example, consider two parallel wires carrying equal and opposite currents: the Amperian loop enclosing both has ∮B⃗·dl⃗ = 0, but B⃗ is non-zero at most points on the loop. The integral being zero only means the positive and negative contributions cancel.", "correct_answer": "B", "concept_tags": ["true-false", "zero-integral", "non-zero-field"], "payload": {"question_id": "cuet-phy-mag-ampere-33", "subtopic": "Line integral of B", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A zero line integral means the net enclosed current is zero, not that B⃗ = 0 everywhere. External currents can produce non-zero B⃗ on the loop while contributing zero net flux.", "misconception": "Equating zero integral with zero field at all points"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "Ampere''s circuital law is the magnetic analogue of Gauss''s law in electrostatics, where the line integral of B⃗ plays the role of the surface integral of E⃗.", "explanation": "This statement is TRUE. Gauss''s law: ∮E⃗·dA⃗ = Q_enc/ε₀ (surface integral of E over a closed surface equals enclosed charge divided by ε₀). Ampere''s law: ∮B⃗·dl⃗ = μ₀I_enc (line integral of B around a closed loop equals μ₀ times enclosed current). Both relate a field integral to an enclosed source, and both are most useful with high symmetry.", "correct_answer": "A", "concept_tags": ["true-false", "gauss-law-analogy", "comparison"], "payload": {"question_id": "cuet-phy-mag-ampere-34", "subtopic": "Comparison with Gauss''s law", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The analogy is well-established: Gauss''s law uses surface integral of E⃗ with enclosed charge, while Ampere''s law uses line integral of B⃗ with enclosed current. Both exploit symmetry.", "misconception": "Not recognizing the structural similarity between the two laws"}]}}]'::jsonb, 'deploy-2026-03-05-b08');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "According to Ampere''s circuital law, ∮B⃗·dl⃗ = ________, where I_enc is the net current enclosed by the Amperian loop.", "explanation": "Ampere''s circuital law states that the line integral of the magnetic field B⃗ around a closed Amperian loop equals μ₀ times the net current enclosed by the loop: ∮B⃗·dl⃗ = μ₀I_enc, where μ₀ = 4π × 10⁻⁷ T·m/A is the permeability of free space.", "correct_answer": "B", "concept_tags": ["fill-in-blanks", "ampere-law-statement", "formula"], "payload": {"question_id": "cuet-phy-mag-ampere-35", "subtopic": "Ampere''s law statement", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀I_enc/(4π)", "is_correct": false}, {"key": "B", "text": "μ₀I_enc", "is_correct": true}, {"key": "C", "text": "I_enc/μ₀", "is_correct": false}, {"key": "D", "text": "μ₀I_enc/(2π)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The factor 4π appears in Biot-Savart law (μ₀/4π), not in Ampere''s circuital law. The law simply gives μ₀I_enc.", "misconception": "Mixing Biot-Savart and Ampere''s law constants"}, {"option_key": "C", "hint": "In Gauss''s law, the constant appears in the denominator (Q/ε₀). In Ampere''s law, μ₀ multiplies I_enc: ∮B⃗·dl⃗ = μ₀I_enc.", "misconception": "Inverting the position of μ₀ by analogy with Gauss''s law"}, {"option_key": "D", "hint": "The 2π factor appears when solving for B of a specific configuration (e.g., B = μ₀I/2πr). The law itself is ∮B⃗·dl⃗ = μ₀I_enc without 2π.", "misconception": "Confusing the general law with a specific application result"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The magnetic field at the centre of a toroid with N turns, mean circumference L, and carrying current I is B = ________.", "explanation": "For a toroid with mean circumference L = 2πR, applying Ampere''s law: B(2πR) = μ₀NI, so B = μ₀NI/(2πR) = μ₀NI/L. This can also be written as B = μ₀nI where n = N/L is the number of turns per unit length along the toroid''s circumference.", "correct_answer": "C", "concept_tags": ["fill-in-blanks", "toroid", "formula"], "payload": {"question_id": "cuet-phy-mag-ampere-36", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀NI", "is_correct": false}, {"key": "B", "text": "μ₀NI/(4πL)", "is_correct": false}, {"key": "C", "text": "μ₀NI/L", "is_correct": true}, {"key": "D", "text": "μ₀I/L", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is missing the division by the circumference L. The Amperian loop has length L = 2πR, so B = μ₀NI/L.", "misconception": "Forgetting the loop length in the denominator"}, {"option_key": "B", "hint": "The 4π factor is extraneous here. Since L = 2πR, B = μ₀NI/(2πR) = μ₀NI/L. No additional 4π appears.", "misconception": "Introducing an unnecessary 4π factor"}, {"option_key": "D", "hint": "The total number of turns N must be included. Each turn carries current I, so the enclosed current is NI, giving B = μ₀NI/L.", "misconception": "Forgetting the number of turns N"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A researcher needs a uniform magnetic field of 0.02 T for an experiment. She decides to use a solenoid with 40 turns per cm and wants to determine the required current. What current must flow through the solenoid?", "explanation": "Converting n = 40 turns/cm = 4000 turns/m. Using B = μ₀nI: I = B/(μ₀n) = 0.02/(4π × 10⁻⁷ × 4000) = 0.02/(16π × 10⁻⁴) = 0.02/(5.027 × 10⁻³) ≈ 3.98 A ≈ 4 A.", "correct_answer": "D", "concept_tags": ["scenario", "solenoid", "numerical", "current-calculation"], "payload": {"question_id": "cuet-phy-mag-ampere-37", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "1 A", "is_correct": false}, {"key": "B", "text": "2 A", "is_correct": false}, {"key": "C", "text": "3 A", "is_correct": false}, {"key": "D", "text": "≈ 4 A", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "With I = 1 A: B = 4π × 10⁻⁷ × 4000 × 1 = 16π × 10⁻⁴ ≈ 5 × 10⁻³ T = 0.005 T, which is four times too small.", "misconception": "Calculation error in unit conversion of n"}, {"option_key": "B", "hint": "With I = 2 A: B ≈ 0.01 T, which is half the required field. The correct current is about 4 A.", "misconception": "Arithmetic error giving half the required value"}, {"option_key": "C", "hint": "With I = 3 A: B ≈ 0.015 T, which is less than 0.02 T. The exact answer is 0.02/(μ₀ × 4000) ≈ 4 A.", "misconception": "Rounding error in the calculation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "Based on the scenario, what is the ratio of the magnetic field at the inner radius to that at the outer radius of the toroid?", "explanation": "The magnetic field inside a toroid at radius r is B = μ₀NI/(2πr). At the inner radius a = 8 cm: B_inner = μ₀NI/(2π × 0.08). At the outer radius b = 12 cm: B_outer = μ₀NI/(2π × 0.12). Ratio = B_inner/B_outer = 0.12/0.08 = 3/2.", "correct_answer": "B", "concept_tags": ["scenario", "toroid", "field-ratio", "radial-variation"], "payload": {"question_id": "cuet-phy-mag-ampere-38", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 : 1", "is_correct": false}, {"key": "B", "text": "3 : 2", "is_correct": true}, {"key": "C", "text": "2 : 3", "is_correct": false}, {"key": "D", "text": "4 : 3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The field is not uniform in a toroid. B ∝ 1/r, so the field is stronger at the inner radius (smaller r).", "misconception": "Treating the toroid field as uniform like a solenoid"}, {"option_key": "C", "hint": "This is the inverse ratio. Since B ∝ 1/r, B_inner/B_outer = r_outer/r_inner = 12/8 = 3/2, not 2/3.", "misconception": "Inverting the ratio (using r_inner/r_outer instead of r_outer/r_inner)"}, {"option_key": "D", "hint": "The ratio depends on the radii: 12/8 = 3/2, not 4/3. Check the given values: inner = 8 cm, outer = 12 cm.", "misconception": "Using incorrect radius values"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "easy", "question_text": "Arrange the following steps in the correct logical order for applying Ampere''s circuital law to find the magnetic field inside a solenoid:", "explanation": "The correct sequence is: (1) Identify the symmetry → the solenoid has translational symmetry along its axis with B uniform inside and zero outside. (2) Choose the Amperian loop → a rectangular loop with one side inside (parallel to axis) and one side outside. (3) Calculate the enclosed current → nLI, where nL turns pass through the loop area. (4) Evaluate the line integral → only the inside parallel side contributes: BL. (5) Apply Ampere''s law → BL = μ₀nLI, giving B = μ₀nI.", "correct_answer": "A", "concept_tags": ["logical-sequence", "solenoid", "methodology"], "payload": {"question_id": "cuet-phy-mag-ampere-39", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Q → P → S → T → R", "is_correct": true}, {"key": "B", "text": "P → Q → T → S → R", "is_correct": false}, {"key": "C", "text": "Q → S → P → R → T", "is_correct": false}, {"key": "D", "text": "S → P → Q → T → R", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "You must identify symmetry (Q) before choosing the loop (P). The loop choice depends on the symmetry identified.", "misconception": "Choosing the loop before understanding the symmetry"}, {"option_key": "C", "hint": "You cannot calculate the enclosed current (S) before choosing the Amperian loop (P), since the enclosed current depends on which loop you choose.", "misconception": "Calculating enclosed current before defining the loop"}, {"option_key": "D", "hint": "Starting with enclosed current calculation (S) is premature. First identify symmetry (Q), then choose the appropriate loop (P).", "misconception": "Jumping to calculation before setting up the problem"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following developments in the correct historical and logical sequence that led from Ampere''s law to Maxwell''s equations:", "explanation": "The correct sequence is: (1) Oersted discovers that electric current produces a magnetic field (1820). (2) Ampere formulates the circuital law relating ∮B⃗·dl⃗ to enclosed current. (3) Gauss''s law is formulated as the electrostatic analogue. (4) Maxwell identifies the inconsistency of Ampere''s law for non-steady currents (charging capacitor problem). (5) Maxwell introduces displacement current and completes the equations.", "correct_answer": "C", "concept_tags": ["logical-sequence", "historical-development", "maxwell-equations", "limitations"], "payload": {"question_id": "cuet-phy-mag-ampere-40", "subtopic": "Limitations", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "S → Q → T → P → R", "is_correct": false}, {"key": "B", "text": "Q → T → S → R → P", "is_correct": false}, {"key": "C", "text": "Q → S → T → P → R", "is_correct": true}, {"key": "D", "text": "T → Q → S → P → R", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Oersted''s discovery (Q) preceded Ampere''s law (S). Oersted first showed current produces magnetism, then Ampere quantified it.", "misconception": "Placing Ampere''s law before Oersted''s discovery"}, {"option_key": "B", "hint": "Maxwell must first identify the inconsistency (P) before introducing the fix — displacement current (R). The order P → R is correct, not R → P.", "misconception": "Reversing the order of identifying the problem and its solution"}, {"option_key": "D", "hint": "Gauss''s law (T) in its general form was developed after Oersted''s discovery (Q) and Ampere''s work (S), not before.", "misconception": "Placing Gauss''s law before the magnetic discoveries"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field inside a long solenoid carrying current I with n turns per unit length is given by:", "explanation": "For an ideal long solenoid, applying Ampere''s circuital law gives B = μ₀nI, where n is the number of turns per unit length, I is the current, and μ₀ is the permeability of free space.", "correct_answer": "A", "concept_tags": ["solenoid", "magnetic field formula", "Ampere''s law"], "payload": {"question_id": "cuet-phy-mag-solenoid-01", "subtopic": "Solenoid field formula (B=μ₀nI)", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "B = μ₀nI", "is_correct": true}, {"key": "B", "value": "B = μ₀NI", "is_correct": false}, {"key": "C", "value": "B = μ₀nI/2π", "is_correct": false}, {"key": "D", "value": "B = μ₀NI/2πr", "is_correct": false}], "elimination_hints": ["B uses total turns N, not turns per unit length n — dimensionally incorrect for the solenoid formula.", "C introduces 2π which appears in toroid/straight wire formulas, not solenoid.", "D is the formula for a toroid, not a solenoid."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field outside an ideal infinitely long solenoid is:", "explanation": "For an ideal solenoid of infinite length, the magnetic field lines are confined entirely within the solenoid. By Ampere''s law, the field outside is zero because no net current is enclosed by an external Amperian loop.", "correct_answer": "B", "concept_tags": ["solenoid", "field outside solenoid"], "payload": {"question_id": "cuet-phy-mag-solenoid-02", "subtopic": "Field inside vs outside solenoid", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "Equal to the field inside", "is_correct": false}, {"key": "B", "value": "Zero", "is_correct": true}, {"key": "C", "value": "Half the field inside", "is_correct": false}, {"key": "D", "value": "Inversely proportional to distance from axis", "is_correct": false}], "elimination_hints": ["A is wrong because the field is concentrated inside, not equally distributed.", "C is arbitrary — there is no half-field relation for an ideal solenoid exterior.", "D describes the field of a long straight wire, not the exterior of a solenoid."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A toroid is essentially a solenoid bent into the shape of a:", "explanation": "A toroid is formed by bending a solenoid into a closed circular ring (doughnut shape). This ensures that the magnetic field is entirely confined within the core with no external field.", "correct_answer": "C", "concept_tags": ["toroid", "solenoid", "geometry"], "payload": {"question_id": "cuet-phy-mag-solenoid-03", "subtopic": "Toroid vs solenoid comparison", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "Straight cylinder", "is_correct": false}, {"key": "B", "value": "Helix", "is_correct": false}, {"key": "C", "value": "Ring (doughnut/torus)", "is_correct": true}, {"key": "D", "value": "Flat disc", "is_correct": false}], "elimination_hints": ["A describes an unbent solenoid itself, not a toroid.", "B describes the winding pattern, not the overall shape of a toroid.", "D is a flat geometry with no enclosed volume for field confinement."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Inserting a ferromagnetic core inside a solenoid increases the magnetic field because:", "explanation": "A ferromagnetic core has high relative permeability (μᵣ >> 1). The field becomes B = μ₀μᵣnI, which is much larger than B = μ₀nI. The core''s domains align with the external field, greatly amplifying it.", "correct_answer": "D", "concept_tags": ["ferromagnetic core", "permeability", "solenoid"], "payload": {"question_id": "cuet-phy-mag-solenoid-04", "subtopic": "Effect of ferromagnetic core", "topic_name": "Solenoid and Toroid", "bloom_level": "understand", "options": [{"key": "A", "value": "It increases the current in the solenoid", "is_correct": false}, {"key": "B", "value": "It increases the number of turns per unit length", "is_correct": false}, {"key": "C", "value": "It reduces the length of the solenoid", "is_correct": false}, {"key": "D", "value": "Its high relative permeability multiplies the field", "is_correct": true}], "elimination_hints": ["A is incorrect — the core does not change the current flowing through the coil.", "B is incorrect — inserting a core does not alter the winding geometry.", "C is incorrect — the physical length of the solenoid remains unchanged."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is a common application of a solenoid?", "explanation": "Solenoids are widely used as electromagnetic door locks, relay switches, MRI machines, and electromagnetic valves. An electromagnetic door lock uses a solenoid-based electromagnet to control the locking mechanism.", "correct_answer": "A", "concept_tags": ["solenoid", "applications", "electromagnet"], "payload": {"question_id": "cuet-phy-mag-solenoid-05", "subtopic": "Applications of solenoids", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "Electromagnetic door lock", "is_correct": true}, {"key": "B", "value": "Electric fuse", "is_correct": false}, {"key": "C", "value": "Rheostat", "is_correct": false}, {"key": "D", "value": "Potentiometer", "is_correct": false}], "elimination_hints": ["B is a safety device based on heating effect, not magnetism.", "C is a variable resistor that does not rely on solenoid principles.", "D measures EMF using the principle of null deflection, unrelated to solenoids."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field inside a toroid of mean radius r, total N turns, carrying current I is:", "explanation": "Applying Ampere''s circuital law to a circular Amperian loop of radius r inside the toroid gives B × 2πr = μ₀NI, so B = μ₀NI/(2πr).", "correct_answer": "B", "concept_tags": ["toroid", "magnetic field", "Ampere''s law"], "payload": {"question_id": "cuet-phy-mag-solenoid-06", "subtopic": "Toroid field formula", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "B = μ₀NI", "is_correct": false}, {"key": "B", "value": "B = μ₀NI/(2πr)", "is_correct": true}, {"key": "C", "value": "B = μ₀nI/r", "is_correct": false}, {"key": "D", "value": "B = μ₀I/(2πr)", "is_correct": false}], "elimination_hints": ["A lacks the 2πr denominator required by Ampere''s law for a toroid.", "C mixes solenoid notation (n) with an extra r factor incorrectly.", "D is the formula for a long straight conductor, missing the N factor."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of length 0.5 m has 1000 turns and carries a current of 2 A. The magnetic field inside the solenoid is approximately:", "explanation": "n = N/L = 1000/0.5 = 2000 turns/m. B = μ₀nI = 4π × 10⁻⁷ × 2000 × 2 = 16π × 10⁻⁴ ≈ 5.03 × 10⁻³ T ≈ 5.0 × 10⁻³ T.", "correct_answer": "C", "concept_tags": ["solenoid", "numerical", "magnetic field calculation"], "payload": {"question_id": "cuet-phy-mag-solenoid-07", "subtopic": "Solenoid field formula (B=μ₀nI)", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "2.5 × 10⁻³ T", "is_correct": false}, {"key": "B", "value": "4.0 × 10⁻³ T", "is_correct": false}, {"key": "C", "value": "5.0 × 10⁻³ T", "is_correct": true}, {"key": "D", "value": "8.0 × 10⁻³ T", "is_correct": false}], "elimination_hints": ["A results from using n = 1000 instead of 2000, i.e., forgetting to divide by length.", "B comes from an arithmetic error in multiplying the factors.", "D is approximately double the correct value."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the current through a solenoid is doubled and the number of turns per unit length is halved, the magnetic field inside the solenoid will:", "explanation": "B = μ₀nI. If n → n/2 and I → 2I, then B'' = μ₀(n/2)(2I) = μ₀nI = B. The magnetic field remains unchanged.", "correct_answer": "D", "concept_tags": ["solenoid", "proportionality", "magnetic field"], "payload": {"question_id": "cuet-phy-mag-solenoid-08", "subtopic": "Solenoid field formula (B=μ₀nI)", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "Double", "is_correct": false}, {"key": "B", "value": "Become four times", "is_correct": false}, {"key": "C", "value": "Become half", "is_correct": false}, {"key": "D", "value": "Remain the same", "is_correct": true}], "elimination_hints": ["A considers only the doubling of current but ignores the halving of n.", "B incorrectly squares the change in current.", "C considers only the halving of n but ignores the doubling of current."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a real (finite-length) solenoid, the magnetic field at the centre compared to that at its ends is approximately:", "explanation": "At the centre of a finite solenoid, B ≈ μ₀nI. At either end, the field is approximately half this value, i.e., B_end ≈ μ₀nI/2, because the solenoid extends in only one direction from the end.", "correct_answer": "A", "concept_tags": ["real solenoid", "finite solenoid", "end effects"], "payload": {"question_id": "cuet-phy-mag-solenoid-09", "subtopic": "Ideal vs real solenoid", "topic_name": "Solenoid and Toroid", "bloom_level": "understand", "options": [{"key": "A", "value": "Twice the field at the ends", "is_correct": true}, {"key": "B", "value": "Equal to the field at the ends", "is_correct": false}, {"key": "C", "value": "Three times the field at the ends", "is_correct": false}, {"key": "D", "value": "Half the field at the ends", "is_correct": false}], "elimination_hints": ["B would only be true for an infinite solenoid where the field is uniform everywhere inside.", "C has no theoretical basis — no factor of 3 arises in solenoid field analysis.", "D reverses the relationship — the centre field is stronger, not weaker."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The self-inductance of a solenoid with N total turns, length l, and cross-sectional area A is given by:", "explanation": "The flux through the solenoid is Φ = NBA = N(μ₀nI)A = N(μ₀N/l)IA = μ₀N²IA/l. Since L = Φ/I, we get L = μ₀N²A/l.", "correct_answer": "B", "concept_tags": ["self-inductance", "solenoid", "inductance formula"], "payload": {"question_id": "cuet-phy-mag-solenoid-10", "subtopic": "Self-inductance relation", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "L = μ₀NA/l", "is_correct": false}, {"key": "B", "value": "L = μ₀N²A/l", "is_correct": true}, {"key": "C", "value": "L = μ₀N²l/A", "is_correct": false}, {"key": "D", "value": "L = μ₀NA²/l", "is_correct": false}], "elimination_hints": ["A is missing the N² dependence — inductance depends on the square of turns.", "C inverts the roles of l and A, giving incorrect dimensions.", "D squares the area instead of the number of turns."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field in the open space inside a toroid (the central empty region) is:", "explanation": "For an Amperian loop drawn inside the central empty region of a toroid, no current is enclosed (the loop does not thread through any turns). By Ampere''s law, B × 2πr = 0, so B = 0.", "correct_answer": "C", "concept_tags": ["toroid", "central region", "Ampere''s law"], "payload": {"question_id": "cuet-phy-mag-solenoid-11", "subtopic": "Toroid field formula", "topic_name": "Solenoid and Toroid", "bloom_level": "understand", "options": [{"key": "A", "value": "Maximum", "is_correct": false}, {"key": "B", "value": "Same as inside the windings", "is_correct": false}, {"key": "C", "value": "Zero", "is_correct": true}, {"key": "D", "value": "Half of the value inside the windings", "is_correct": false}], "elimination_hints": ["A is wrong — the field is confined to the toroid''s core, not the central space.", "B confuses the central hollow region with the core where windings exist.", "D has no theoretical basis; no half-field relation applies here."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of length 1 m with 500 turns carries 4 A of current. If a soft iron core of relative permeability 800 is inserted, the magnetic field inside becomes approximately:", "explanation": "n = 500/1 = 500 turns/m. Without core: B₀ = μ₀nI = 4π × 10⁻⁷ × 500 × 4 = 8π × 10⁻⁴ T ≈ 2.51 × 10⁻³ T. With core: B = μᵣB₀ = 800 × 2.51 × 10⁻³ ≈ 2.01 T ≈ 2.0 T.", "correct_answer": "D", "concept_tags": ["ferromagnetic core", "relative permeability", "numerical"], "payload": {"question_id": "cuet-phy-mag-solenoid-12", "subtopic": "Effect of ferromagnetic core", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "2.5 × 10⁻³ T", "is_correct": false}, {"key": "B", "value": "0.25 T", "is_correct": false}, {"key": "C", "value": "0.5 T", "is_correct": false}, {"key": "D", "value": "2.0 T", "is_correct": true}], "elimination_hints": ["A is the field without the core — the core amplifies it by factor μᵣ = 800.", "B results from an error in the multiplication by the permeability factor.", "C underestimates the amplification provided by the iron core."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which statement correctly distinguishes a solenoid from a toroid?", "explanation": "A key difference is that a toroid has zero magnetic field outside its core (both in the central region and exterior), while a real solenoid has a weak but non-zero field outside, especially near its ends.", "correct_answer": "A", "concept_tags": ["solenoid", "toroid", "comparison"], "payload": {"question_id": "cuet-phy-mag-solenoid-13", "subtopic": "Toroid vs solenoid comparison", "topic_name": "Solenoid and Toroid", "bloom_level": "understand", "options": [{"key": "A", "value": "A toroid has no external magnetic field, whereas a real solenoid has a weak external field", "is_correct": true}, {"key": "B", "value": "A solenoid always has stronger internal field than a toroid for identical parameters", "is_correct": false}, {"key": "C", "value": "A toroid requires no current to produce a magnetic field", "is_correct": false}, {"key": "D", "value": "The field inside a solenoid depends on its radius but not in a toroid", "is_correct": false}], "elimination_hints": ["B cannot be generally compared as the geometries and formulas differ fundamentally.", "C violates basic electromagnetic principles — current is always needed for a magnetic field.", "D is reversed — an ideal solenoid''s field is radius-independent, while a toroid''s field depends on radial position."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field inside an ideal solenoid is:", "explanation": "Inside an ideal (infinite) solenoid, the magnetic field is uniform and parallel to the axis. It does not depend on the radial position within the solenoid. This is derived from Ampere''s law using a rectangular Amperian loop.", "correct_answer": "B", "concept_tags": ["ideal solenoid", "uniform field", "field properties"], "payload": {"question_id": "cuet-phy-mag-solenoid-14", "subtopic": "Ideal vs real solenoid", "topic_name": "Solenoid and Toroid", "bloom_level": "understand", "options": [{"key": "A", "value": "Non-uniform and radial", "is_correct": false}, {"key": "B", "value": "Uniform and parallel to the axis", "is_correct": true}, {"key": "C", "value": "Uniform and perpendicular to the axis", "is_correct": false}, {"key": "D", "value": "Zero at the centre and maximum near the walls", "is_correct": false}], "elimination_hints": ["A describes a field pattern that would violate the symmetry of the solenoid.", "C has the wrong direction — the field is along the axis, not perpendicular.", "D reverses the actual behaviour — the field is uniform throughout the interior."]}}]'::jsonb, 'deploy-2026-03-05-b08');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the length of a solenoid is doubled while keeping the total number of turns and current constant, the magnetic field inside will:", "explanation": "B = μ₀nI = μ₀(N/l)I. If l → 2l with N and I constant, then n → N/(2l) = n/2. Therefore B'' = μ₀(n/2)I = B/2. The field is halved.", "correct_answer": "C", "concept_tags": ["solenoid", "proportionality", "turns per unit length"], "payload": {"question_id": "cuet-phy-mag-solenoid-15", "subtopic": "Solenoid field formula (B=μ₀nI)", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "Double", "is_correct": false}, {"key": "B", "value": "Remain the same", "is_correct": false}, {"key": "C", "value": "Become half", "is_correct": true}, {"key": "D", "value": "Become one-fourth", "is_correct": false}], "elimination_hints": ["A incorrectly assumes B is proportional to length.", "B ignores the change in turns per unit length when length changes.", "D would require both n and I to be halved, which is not the case."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A toroid with 2000 turns, mean radius 20 cm, carries a current of 5 A. The magnetic field at the centre of the toroid (in the empty space enclosed by the ring) is:", "explanation": "The magnetic field in the central open space of a toroid is zero. An Amperian loop drawn in this region does not enclose any current, so by Ampere''s law B = 0. The given numerical values are distractors.", "correct_answer": "D", "concept_tags": ["toroid", "central region", "Ampere''s law", "tricky"], "payload": {"question_id": "cuet-phy-mag-solenoid-16", "subtopic": "Toroid field formula", "topic_name": "Solenoid and Toroid", "bloom_level": "analyze", "options": [{"key": "A", "value": "10⁻² T", "is_correct": false}, {"key": "B", "value": "10⁻³ T", "is_correct": false}, {"key": "C", "value": "2 × 10⁻³ T", "is_correct": false}, {"key": "D", "value": "Zero", "is_correct": true}], "elimination_hints": ["A results from blindly applying B = μ₀NI/(2πr) without noting the region asked about.", "B is a numerical distractor that does not correspond to any valid calculation for this region.", "C is another distractor — any non-zero value is wrong for the central empty space."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two solenoids P and Q have the same length and carry the same current. P has twice the number of turns as Q but half the cross-sectional area. The ratio of their self-inductances L_P/L_Q is:", "explanation": "L = μ₀N²A/l. For P: L_P = μ₀(2N)²(A/2)/l = μ₀ × 4N² × A/(2l) = 2μ₀N²A/l. For Q: L_Q = μ₀N²A/l. So L_P/L_Q = 2.", "correct_answer": "C", "concept_tags": ["self-inductance", "solenoid", "ratio", "comparison"], "payload": {"question_id": "cuet-phy-mag-solenoid-17", "subtopic": "Self-inductance relation", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "1:1", "is_correct": false}, {"key": "B", "value": "4:1", "is_correct": false}, {"key": "C", "value": "2:1", "is_correct": true}, {"key": "D", "value": "1:2", "is_correct": false}], "elimination_hints": ["A ignores the effect of different N and A values on inductance.", "B considers only the N² factor (4×) but forgets the halved area.", "D inverts the ratio — P has larger inductance, not smaller."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A solenoid is connected to a battery. If a soft iron rod is partially inserted into the solenoid, the rod will:", "explanation": "The magnetic field inside the solenoid is non-uniform at the ends. A ferromagnetic material is attracted towards regions of stronger field. The iron rod will be pulled inward towards the region of stronger and more uniform field.", "correct_answer": "A", "concept_tags": ["solenoid", "ferromagnetic", "force on core", "non-uniform field"], "payload": {"question_id": "cuet-phy-mag-solenoid-18", "subtopic": "Effect of ferromagnetic core", "topic_name": "Solenoid and Toroid", "bloom_level": "analyze", "options": [{"key": "A", "value": "Be pulled further inside the solenoid", "is_correct": true}, {"key": "B", "value": "Be pushed out of the solenoid", "is_correct": false}, {"key": "C", "value": "Remain stationary at its position", "is_correct": false}, {"key": "D", "value": "Start rotating about the solenoid axis", "is_correct": false}], "elimination_hints": ["B would occur for a diamagnetic material, not a ferromagnetic one.", "C ignores the force exerted by the non-uniform field on the magnetised rod.", "D has no physical basis — the axial symmetry produces no torque about the axis."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A toroid of inner radius 10 cm and outer radius 14 cm has 1500 turns and carries 3 A. The magnetic field at a radial distance of 16 cm from the centre of the toroid is:", "explanation": "The outer radius of the toroid is 14 cm. A point at 16 cm lies outside the toroid. For an Amperian loop outside the toroid, the net enclosed current is zero. Therefore B = 0 outside the toroid.", "correct_answer": "B", "concept_tags": ["toroid", "external field", "Ampere''s law"], "payload": {"question_id": "cuet-phy-mag-solenoid-19", "subtopic": "Toroid field formula", "topic_name": "Solenoid and Toroid", "bloom_level": "analyze", "options": [{"key": "A", "value": "5.6 × 10⁻³ T", "is_correct": false}, {"key": "B", "value": "Zero", "is_correct": true}, {"key": "C", "value": "2.8 × 10⁻³ T", "is_correct": false}, {"key": "D", "value": "1.4 × 10⁻³ T", "is_correct": false}], "elimination_hints": ["A results from using the toroid formula at r = 16 cm without recognising the point is outside.", "C is a computational distractor based on incorrect radius substitution.", "D is another numerical distractor — any non-zero answer is wrong outside the toroid."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The energy stored per unit volume inside a solenoid is u = B²/(2μ₀). If the current through the solenoid is tripled, the energy density becomes:", "explanation": "B = μ₀nI, so B is proportional to I. Energy density u = B²/(2μ₀) is proportional to I². If I → 3I, then u → 9u. The energy density becomes 9 times the original value.", "correct_answer": "D", "concept_tags": ["energy density", "solenoid", "magnetic energy"], "payload": {"question_id": "cuet-phy-mag-solenoid-20", "subtopic": "Solenoid field formula (B=μ₀nI)", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "3 times the original", "is_correct": false}, {"key": "B", "value": "6 times the original", "is_correct": false}, {"key": "C", "value": "27 times the original", "is_correct": false}, {"key": "D", "value": "9 times the original", "is_correct": true}], "elimination_hints": ["A only considers the linear change in I, ignoring the B² dependence.", "B has no theoretical basis — 6 does not arise from squaring or cubing 3.", "C cubes instead of squaring — energy density depends on I², not I³."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A proton moving with velocity v enters a uniform magnetic field B perpendicular to its direction of motion. The path followed by the proton is:", "explanation": "When a charged particle enters a magnetic field perpendicular to its velocity, the magnetic force F = qv × B acts as a centripetal force. Since this force is always perpendicular to the velocity, it changes the direction but not the speed of the particle. This results in uniform circular motion. The radius of the circle is r = mv/(qB).", "correct_answer": "C", "concept_tags": ["circular-motion", "lorentz-force", "charged-particle-in-B"], "payload": {"question_id": "cuet-phy-mag-force-01", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "A straight line", "is_correct": false}, {"key": "B", "text": "A parabolic path", "is_correct": false}, {"key": "C", "text": "A circular path", "is_correct": true}, {"key": "D", "text": "A helical path", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A straight line would occur only if the velocity were parallel to B (zero force). Here v is perpendicular to B.", "misconception": "Thinking magnetic force does not deflect the particle"}, {"option_key": "B", "hint": "A parabolic path occurs under a constant force (like gravity). The magnetic force changes direction continuously, unlike gravity.", "misconception": "Confusing magnetic force with gravitational force"}, {"option_key": "D", "hint": "A helical path requires a velocity component along B. Since v is entirely perpendicular to B, the path is circular, not helical.", "misconception": "Assuming helical motion without a parallel velocity component"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The work done by a magnetic force on a charged particle moving in a magnetic field is:", "explanation": "The magnetic force F = qv × B is always perpendicular to the velocity of the charged particle. Since work done W = F · ds = F · v dt, and F is perpendicular to v, the dot product F · v = 0. Hence, the magnetic force does no work on a moving charge. It can only change the direction of velocity, not its magnitude.", "correct_answer": "C", "concept_tags": ["work-done", "magnetic-force", "perpendicular-force"], "payload": {"question_id": "cuet-phy-mag-force-02", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Positive", "is_correct": false}, {"key": "B", "text": "Negative", "is_correct": false}, {"key": "C", "text": "Always zero", "is_correct": true}, {"key": "D", "text": "Depends on the magnitude of charge", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Magnetic force is always perpendicular to velocity. A perpendicular force cannot increase the kinetic energy or do positive work.", "misconception": "Assuming any force that acts on a moving particle does work"}, {"option_key": "B", "hint": "Negative work would slow down the particle. But the speed of a charged particle in a pure magnetic field remains constant.", "misconception": "Confusing magnetic force with a drag or resistive force"}, {"option_key": "D", "hint": "Regardless of the magnitude of charge, the magnetic force is always perpendicular to displacement, so work is always zero.", "misconception": "Thinking work depends on charge magnitude alone"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A straight conductor of length 0.5 m carrying a current of 2 A is placed perpendicular to a uniform magnetic field of 0.4 T. The force experienced by the conductor is:", "explanation": "Using F = BIL sinθ, where B = 0.4 T, I = 2 A, L = 0.5 m, and θ = 90° (perpendicular). F = 0.4 × 2 × 0.5 × sin90° = 0.4 × 2 × 0.5 × 1 = 0.4 N.", "correct_answer": "A", "concept_tags": ["force-on-conductor", "BIL-formula", "perpendicular-field"], "payload": {"question_id": "cuet-phy-mag-force-03", "subtopic": "force on current-carrying conductor (F=BIL sinθ)", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "0.4 N", "is_correct": true}, {"key": "B", "text": "0.2 N", "is_correct": false}, {"key": "C", "text": "0.8 N", "is_correct": false}, {"key": "D", "text": "0.1 N", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This would result from using sinθ = 0.5 (i.e., θ = 30°), but the conductor is perpendicular to the field so sinθ = 1.", "misconception": "Using wrong angle in F = BIL sinθ"}, {"option_key": "C", "hint": "This is double the correct answer. Check that you are not multiplying any quantity twice.", "misconception": "Arithmetic error in multiplication"}, {"option_key": "D", "hint": "This is one-fourth of the correct value. Verify all substituted values: B = 0.4, I = 2, L = 0.5.", "misconception": "Incorrect substitution of given values"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A charged particle moving with velocity v enters a uniform magnetic field B perpendicular to its velocity. The magnetic force on the particle is:", "explanation": "The magnetic force on a moving charged particle is given by F = qv × B. When the velocity is perpendicular to the magnetic field (θ = 90°), sin 90° = 1, so F = qvB. This is the maximum force the magnetic field can exert on the charge.", "correct_answer": "A", "concept_tags": ["lorentz-force", "magnetic-force", "moving-charge"], "payload": {"question_id": "cuet-phy-mag-force-04", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "qvB", "is_correct": true}, {"key": "B", "text": "qvB/2", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "qv/B", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The factor of 1/2 does not appear in the Lorentz force formula. F = qvB sinθ has no such coefficient.", "misconception": "Confusing with kinetic energy formula which has a 1/2 factor"}, {"option_key": "C", "hint": "Force is zero only when the charge moves parallel to B (θ = 0°). Here the motion is perpendicular to B, so sinθ = 1.", "misconception": "Confusing perpendicular and parallel motion relative to B"}, {"option_key": "D", "hint": "Dimensionally, qv/B gives C·m/(s·T) which does not have units of force. The correct formula has B in the numerator.", "misconception": "Incorrectly placing B in the denominator"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Two long parallel conductors carry currents in the same direction. The force between them is:", "explanation": "When two parallel conductors carry currents in the same direction, the magnetic field produced by one conductor at the location of the other results in an attractive force between them. This can be verified using the right-hand rule: the field from one wire at the other wire''s location creates a force directed toward the first wire. Currents in opposite directions repel each other.", "correct_answer": "A", "concept_tags": ["parallel-conductors", "force-between-conductors", "attractive-force"], "payload": {"question_id": "cuet-phy-mag-force-05", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "Attractive", "is_correct": true}, {"key": "B", "text": "Repulsive", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "Attractive or repulsive depending on the magnitude of currents", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Repulsive force occurs between parallel conductors carrying currents in opposite directions. Same-direction currents always attract.", "misconception": "Confusing same-direction and opposite-direction current rules"}, {"option_key": "C", "hint": "Two current-carrying conductors always exert a force on each other. The force is zero only when one of the currents is zero.", "misconception": "Thinking parallel conductors do not interact magnetically"}, {"option_key": "D", "hint": "The nature of the force (attractive/repulsive) depends only on the relative direction of currents, not on their magnitudes.", "misconception": "Confusing the nature of force with its magnitude"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A proton moves parallel to a uniform magnetic field. The force acting on the proton is:", "explanation": "The magnetic force on a charged particle is F = qvB sinθ. When the particle moves parallel to B, the angle θ = 0°, and sin 0° = 0. Therefore, F = 0. A magnetic field exerts no force on a charge moving along the field direction.", "correct_answer": "B", "concept_tags": ["magnetic-force", "parallel-motion", "zero-force"], "payload": {"question_id": "cuet-phy-mag-force-06", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "qvB", "is_correct": false}, {"key": "B", "text": "Zero", "is_correct": true}, {"key": "C", "text": "qvB/2", "is_correct": false}, {"key": "D", "text": "qB/v", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "F = qvB applies only when v is perpendicular to B (θ = 90°). Here the motion is parallel, so sinθ = 0.", "misconception": "Ignoring the sinθ dependence in the Lorentz force"}, {"option_key": "C", "hint": "There is no 1/2 factor in the force formula, and regardless the force is zero when velocity is parallel to B.", "misconception": null}, {"option_key": "D", "hint": "This expression is dimensionally incorrect for force and does not correspond to any known formula.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a velocity selector, electric and magnetic fields are applied perpendicular to each other and to the velocity of charged particles. A particle passes through undeflected when:", "explanation": "In a velocity selector, the electric force qE and the magnetic force qvB act in opposite directions on the charged particle. For the particle to pass undeflected, these forces must balance: qE = qvB, giving v = E/B. This condition is independent of the charge and mass of the particle, so only particles with velocity v = E/B pass through straight.", "correct_answer": "C", "concept_tags": ["velocity-selector", "electric-magnetic-balance", "undeflected-motion"], "payload": {"question_id": "cuet-phy-mag-force-07", "subtopic": "velocity selector", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "v = B/E", "is_correct": false}, {"key": "B", "text": "v = EB", "is_correct": false}, {"key": "C", "text": "v = E/B", "is_correct": true}, {"key": "D", "text": "v = E²/B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the inverse of the correct relation. From qE = qvB, solve for v: v = E/B, not B/E.", "misconception": "Inverting the ratio when solving qE = qvB"}, {"option_key": "B", "hint": "Check dimensions: EB has units of V·T/m, which is not velocity. v = E/B has units (V/m)/(T) = m/s.", "misconception": "Multiplying instead of dividing E and B"}, {"option_key": "D", "hint": "This has incorrect dimensions. The balance condition qE = qvB gives a linear relation between v, E, and B.", "misconception": "Introducing an incorrect power of E"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electron (charge e, mass m) and a proton (charge e, mass M) enter a uniform magnetic field perpendicularly with the same kinetic energy. The ratio of radii of their circular paths (rₑ/rₚ) is:", "explanation": "The radius of circular motion in a magnetic field is r = mv/(eB). Since kinetic energy K = ½mv², we get v = √(2K/m), so r = m√(2K/m)/(eB) = √(2mK)/(eB). Therefore rₑ/rₚ = √(m/M). Since the electron mass m is much smaller than proton mass M, the electron follows a much smaller circle.", "correct_answer": "C", "concept_tags": ["radius-ratio", "kinetic-energy", "electron", "proton", "circular-motion"], "payload": {"question_id": "cuet-phy-mag-force-08", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "m/M", "is_correct": false}, {"key": "B", "text": "M/m", "is_correct": false}, {"key": "C", "text": "√(m/M)", "is_correct": true}, {"key": "D", "text": "√(M/m)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This would be the ratio if r were directly proportional to mass (at same velocity). But at same kinetic energy, r = √(2mK)/(eB), giving a square-root dependence.", "misconception": "Using r = mv/(qB) without converting velocity in terms of kinetic energy"}, {"option_key": "B", "hint": "M/m > 1 would mean the electron has a larger radius than the proton, which contradicts the fact that the lighter particle has a smaller radius at equal KE.", "misconception": "Inverting the mass ratio"}, {"option_key": "D", "hint": "√(M/m) > 1 would imply rₑ > rₚ. Since the electron is lighter, it has less momentum at the same KE and hence a smaller radius.", "misconception": "Confusing which particle has the larger radius"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a velocity selector, a charged particle passes undeflected when:", "explanation": "In a velocity selector, crossed electric (E) and magnetic (B) fields are applied. The electric force qE and the magnetic force qvB act in opposite directions. The particle passes undeflected when these forces balance: qE = qvB, giving v = E/B. This condition is independent of the charge and mass of the particle.", "correct_answer": "C", "concept_tags": ["velocity-selector", "electric-field", "magnetic-field", "undeflected"], "payload": {"question_id": "cuet-phy-mag-force-09", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "v = B/E", "is_correct": false}, {"key": "B", "text": "v = EB", "is_correct": false}, {"key": "C", "text": "v = E/B", "is_correct": true}, {"key": "D", "text": "v = E²/B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "B/E is the inverse of the correct answer. From qE = qvB, solving for v gives v = E/B, not B/E.", "misconception": "Inverting the ratio while solving qE = qvB"}, {"option_key": "B", "hint": "EB is dimensionally incorrect for velocity. E has units V/m and B has units T, so EB would have units V·T/m, not m/s.", "misconception": "Incorrectly combining E and B"}, {"option_key": "D", "hint": "E²/B does not follow from balancing electric and magnetic forces. The correct derivation gives v = E/B.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charged particle of mass m and charge q moves in a circular orbit of radius r in a magnetic field B. The kinetic energy of the particle is:", "explanation": "For circular motion in a magnetic field: qvB = mv²/r, giving v = qBr/m. The kinetic energy is KE = ½mv² = ½m(qBr/m)² = q²B²r²/(2m). This shows that the kinetic energy depends on the square of the charge, field, and radius, and inversely on the mass.", "correct_answer": "D", "concept_tags": ["circular-motion", "kinetic-energy", "radius-momentum-relation"], "payload": {"question_id": "cuet-phy-mag-force-10", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "qBr/m", "is_correct": false}, {"key": "B", "text": "q²B²r/(2m)", "is_correct": false}, {"key": "C", "text": "qB²r²/(2m)", "is_correct": false}, {"key": "D", "text": "q²B²r²/(2m)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This has dimensions of velocity, not energy. Kinetic energy must have dimensions of kg·m²/s².", "misconception": "Confusing velocity with kinetic energy"}, {"option_key": "B", "hint": "Check the power of r. From v = qBr/m, v² involves r², not r.", "misconception": "Missing a factor of r in the derivation"}, {"option_key": "C", "hint": "Check the power of q. From v = qBr/m, v² involves q², not q.", "misconception": "Missing a factor of q in the derivation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a cyclotron, a proton is accelerated to high speeds. The time period of revolution of the proton in the magnetic field is independent of:", "explanation": "In a cyclotron, the time period T = 2πm/(qB). This expression shows that T depends on the mass m, charge q, and magnetic field B, but is independent of the speed (or kinetic energy) of the particle and the radius of its circular path. This independence of speed from the time period is the fundamental principle that allows the cyclotron to work with a fixed-frequency oscillating electric field.", "correct_answer": "A", "concept_tags": ["cyclotron", "time-period", "frequency-independence"], "payload": {"question_id": "cuet-phy-mag-force-11", "subtopic": "cyclotron", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Speed and radius of the circular path", "is_correct": true}, {"key": "B", "text": "Mass of the particle", "is_correct": false}, {"key": "C", "text": "Charge of the particle", "is_correct": false}, {"key": "D", "text": "Magnetic field strength", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "T = 2πm/(qB) explicitly contains m in the numerator. Changing the mass changes the time period.", "misconception": "Thinking mass does not affect the cyclotron frequency"}, {"option_key": "C", "hint": "T = 2πm/(qB) contains q in the denominator. Changing the charge changes the time period.", "misconception": "Thinking charge does not affect the cyclotron frequency"}, {"option_key": "D", "hint": "T = 2πm/(qB) contains B in the denominator. A stronger field means a shorter time period.", "misconception": "Thinking the magnetic field does not affect the time period"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A straight conductor of length 0.5 m carrying a current of 2 A is placed in a uniform magnetic field of 0.4 T at an angle of 30° to the field. The force on the conductor is:", "explanation": "The force on a current-carrying conductor in a magnetic field is F = BIL sinθ. Substituting the given values: F = 0.4 × 2 × 0.5 × sin 30° = 0.4 × 2 × 0.5 × 0.5 = 0.2 N.", "correct_answer": "D", "concept_tags": ["force-on-conductor", "current-carrying-conductor", "magnetic-field", "numerical"], "payload": {"question_id": "cuet-phy-mag-force-12", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "0.4 N", "is_correct": false}, {"key": "B", "text": "0.1 N", "is_correct": false}, {"key": "C", "text": "0.8 N", "is_correct": false}, {"key": "D", "text": "0.2 N", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0.4 N would be the answer if sinθ = 1 (θ = 90°). Here θ = 30°, so sin 30° = 0.5 must be included.", "misconception": "Forgetting the sinθ factor when the conductor is not perpendicular to B"}, {"option_key": "B", "hint": "0.1 N would result from using sin 30° twice or an arithmetic error. Check: F = 0.4 × 2 × 0.5 × 0.5 = 0.2 N.", "misconception": "Arithmetic error in multiplication"}, {"option_key": "C", "hint": "0.8 N would result from ignoring sin 30° and also doubling the result. F = BIL sinθ, not 2BIL.", "misconception": "Using an incorrect formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charged particle moves in a helical path in a uniform magnetic field. This happens when the velocity of the particle:", "explanation": "When a charged particle enters a magnetic field with its velocity at an angle to the field (neither parallel nor perpendicular), the velocity component perpendicular to B causes circular motion while the component parallel to B remains unaffected. The combination of circular motion and uniform linear motion along B produces a helical (spiral) path.", "correct_answer": "D", "concept_tags": ["helical-motion", "velocity-components", "magnetic-field"], "payload": {"question_id": "cuet-phy-mag-force-13", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Is perpendicular to B", "is_correct": false}, {"key": "B", "text": "Is parallel to B", "is_correct": false}, {"key": "C", "text": "Is zero", "is_correct": false}, {"key": "D", "text": "Has components both parallel and perpendicular to B", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "When velocity is purely perpendicular to B, the particle follows a circular path, not a helical one.", "misconception": "Confusing circular and helical paths"}, {"option_key": "B", "hint": "When velocity is parallel to B, there is no magnetic force and the particle moves in a straight line.", "misconception": "Not recognizing that parallel motion produces zero force"}, {"option_key": "C", "hint": "If velocity is zero, there is no motion at all and hence no path of any kind.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two long parallel wires separated by a distance of 0.1 m carry currents of 5 A and 10 A in the same direction. The force per unit length between them is: (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "The force per unit length between two parallel current-carrying wires is F/L = μ₀I₁I₂/(2πd). Substituting: F/L = (4π × 10⁻⁷ × 5 × 10)/(2π × 0.1) = (4π × 10⁻⁷ × 50)/(0.2π) = (200π × 10⁻⁷)/(0.2π) = 1000 × 10⁻⁷ = 10⁻⁴ N/m = 1 × 10⁻⁴ N/m. Since the currents are in the same direction, the force is attractive.", "correct_answer": "B", "concept_tags": ["parallel-currents", "force-per-unit-length", "attractive-force"], "payload": {"question_id": "cuet-phy-mag-force-14", "subtopic": "force between parallel currents", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "2 × 10⁻⁴ N/m, repulsive", "is_correct": false}, {"key": "B", "text": "1 × 10⁻⁴ N/m, attractive", "is_correct": true}, {"key": "C", "text": "1 × 10⁻⁴ N/m, repulsive", "is_correct": false}, {"key": "D", "text": "5 × 10⁻⁵ N/m, attractive", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Check your calculation. The factor 2π in the denominator should give 10⁻⁴, not 2 × 10⁻⁴. Also, same-direction currents attract.", "misconception": "Error in simplifying the 2π factor"}, {"option_key": "C", "hint": "The magnitude is correct, but same-direction currents attract each other, they do not repel.", "misconception": "Confusing the direction of force between parallel currents"}, {"option_key": "D", "hint": "This is half the correct value. Verify your substitution of I₁ and I₂ in the formula.", "misconception": "Using incorrect current values in the formula"}]}}]'::jsonb, 'deploy-2026-03-05-b08');

